class Handler(BaseHTTPRequestHandler):
    def do_GET(self) -> None:
        parsed_url = urlparse(self.path)
        path = parsed_url.path
        email = current_email(self)
        REQUEST_EMAIL.set(email)
        if path in {"/rps", "/longhubang", "/api/rps", "/api/longhubang_rank"}:
            self.send_error(404)
            return
        if self._requires_login(path) and not email:
            if path.startswith("/api/"):
                self._send_json({"ok": False, "loggedIn": False, "message": "请先登录后使用。"}, status=401)
            else:
                target = "/admin/login" if path == "/admin" else f"/login?next={urllib.parse.quote(self.path or '/', safe='')}"
                self._redirect(target)
            return
        if path.startswith("/assets/") or path.startswith("/static/"):
            self._send_asset(path)
            return
        if path in {"/", "/index.html", "/landing"}:
            self._send_html(LANDING_HTML)
            return
        if path == "/home":
            self._send_html(LANDING_HTML)
            return
        if path == "/app":
            self._send_html(HTML)
            return
        if path == "/market-radar":
            self._send_html(MARKET_RADAR_HTML)
            return
        if path == "/commercial":
            self._send_html(COMMERCIAL_CLEAN_HTML)
            return
        if path == "/login":
            self._send_html(AUTH_HTML.replace("__MODE__", "login"))
            return
        if path == "/register":
            self._send_html(AUTH_HTML.replace("__MODE__", "register"))
            return
        if path == "/account":
            self._send_html(ACCOUNT_HTML)
            return
        if path == "/admin/login":
            ensure_admin_account()
            self._send_html(ADMIN_LOGIN_HTML)
            return
        if path == "/recharge":
            self._send_html(RECHARGE_HTML)
            return
        if path == "/admin":
            if not is_admin_email(email):
                self._send_html(FORBIDDEN_HTML, status=403)
                return
            self._send_html(ADMIN_HTML)
            return
        if path == "/research":
            self._send_html(RESEARCH_HTML)
            return
        if path == "/longhubang":
            self._send_html(LONGHUBANG_HTML)
            return
        if path == "/rps":
            self._send_html(RPS_HTML)
            return
        if path == "/simulation":
            self._send_html(SIMULATION_HTML)
            return
        if path == "/ranking":
            self._send_html(AUTO_T_RANKING_HTML)
            return
        if path == "/api/status":
            self._send_json({"ok": True, "message": "就绪"})
            return
        if path == "/api/realtime":
            self._send_json(realtime_payload(email))
            return
        if path == "/api/market_radar":
            self._send_json(market_radar_payload(email))
            return
        if path == "/api/auto_t_ranking":
            self._send_json(auto_t_ranking_payload(email))
            return
        if path == "/api/premarket":
            query = parse_qs(parsed_url.query)
            code = (query.get("code") or [""])[0]
            self._send_json(premarket_payload(code, email))
            return
        if path == "/api/watchlist":
            self._send_json(watchlist_payload(email))
            return
        if path == "/api/wechat_messages":
            self._send_json(wechat_messages_payload())
            return
        if path == "/api/screener":
            query = parse_qs(parsed_url.query)
            mode = (query.get("mode") or ["local"])[0]
            self._send_json(without_retired_research_fields(screener_payload_v2(mode)))
            return
        if path == "/api/longhubang_rank":
            query = parse_qs(parsed_url.query)
            limit = clamp_int((query.get("limit") or ["30"])[0], 30, 5, 80)
            self._send_json(longhubang_rank_payload(limit))
            return
        if path == "/api/rps":
            query = parse_qs(parsed_url.query)
            limit = clamp_int((query.get("limit") or ["10"])[0], 10, 5, 30)
            self._send_json(rps_payload(limit))
            return
        if path == "/api/single_research":
            query = parse_qs(parsed_url.query)
            code = (query.get("code") or [""])[0]
            mode = (query.get("mode") or ["local"])[0]
            self._send_json(without_retired_research_fields(single_research_payload(code, mode)))
            return
        if path == "/api/gemini_status":
            self._send_json(gemini_status_payload())
            return
        if path == "/api/gemini_intraday":
            query = parse_qs(parsed_url.query)
            code = (query.get("code") or [""])[0]
            self._send_json(gemini_intraday_payload(code))
            return
        if path == "/api/settings":
            self._send_json(load_dashboard_settings(email))
            return
        if path == "/api/account":
            self._send_json(account_payload(self))
            return
        if path == "/api/admin/users":
            if not is_admin_email(email):
                self._send_json({"ok": False, "message": "没有管理员权限。"}, status=403)
                return
            self._send_json(admin_users_payload())
            return
        if path == "/api/admin/activation_codes":
            if not is_admin_email(email):
                self._send_json({"ok": False, "message": "没有管理员权限。"}, status=403)
                return
            self._send_json(admin_activation_codes_payload())
            return
        if path == "/api/simulation_history":
            self._send_json({"ok": True, "history": aggregate_sim_history(email), "runs": recent_sim_history(12, email), "latest": latest_sim_result(email), "smartTReview": smart_t_review_payload(email)})
            return
        if path == "/api/adaptive/profile":
            query = parse_qs(parsed_url.query)
            profile = normalize_smart_profile((query.get("profile") or ["balanced"])[0])
            try:
                self._send_json(profile_status(profile_learning_path(email, profile), profile))
            except Exception as exc:
                self._send_json({"ok": False, "message": f"策略成长状态读取失败：{exc}"}, status=500)
            return
        self.send_error(404)

    def do_POST(self) -> None:
        path = urlparse(self.path).path
        email = current_email(self)
        REQUEST_EMAIL.set(email)
        if self._requires_login(path) and not email:
            self._send_json({"ok": False, "loggedIn": False, "message": "请先登录后使用。"}, status=401)
            return
        if path.startswith("/api/run/"):
            name = path.rsplit("/", 1)[-1]
            self._send_json(run_task(name, self._read_json()))
            return
        if path == "/api/settings":
            self._send_json(save_dashboard_settings(self._read_json(), email))
            return
        if path == "/api/account/avatar":
            self._send_json(save_account_avatar(email, self._read_json()))
            return
        if path == "/api/watchlist":
            self._send_json(save_watchlist_payload(self._read_json(), email))
            return
        if path == "/api/register":
            payload = register_payload(self, self._read_json())
            if payload is not None:
                self._send_json(payload)
            return
        if path == "/api/login":
            payload = login_payload(self, self._read_json())
            if payload is not None:
                self._send_json(payload)
            return
        if path == "/api/admin/login":
            try:
                payload = admin_login_payload(self, self._read_json())
                if payload is not None:
                    self._send_json(payload)
            except Exception as exc:
                self._send_json({"ok": False, "message": f"管理员登录接口异常：{exc}"}, status=500)
            return
        if path == "/api/logout":
            logout_payload(self)
            return
        if path == "/api/redeem":
            self._send_json(redeem_activation_payload(email, self._read_json()))
            return
        if path == "/api/admin/activation_codes":
            if not is_admin_email(email):
                self._send_json({"ok": False, "message": "没有管理员权限。"}, status=403)
                return
            self._send_json(create_activation_codes_payload(email, self._read_json()))
            return
        if path in {"/api/adaptive/promote", "/api/adaptive/rollback"}:
            data = self._read_json()
            profile = normalize_smart_profile(data.get("profile"))
            try:
                if path.endswith("promote"):
                    payload = promote_profile(profile_learning_path(email, profile), profile)
                else:
                    payload = rollback_profile(profile_learning_path(email, profile), profile, str(data.get("version") or ""))
                self._send_json(payload, status=200 if payload.get("ok") else 409)
            except Exception as exc:
                self._send_json({"ok": False, "message": f"策略版本操作失败：{exc}"}, status=500)
            return
        self.send_error(404)

    def log_message(self, _format: str, *args: object) -> None:
        return

    def _requires_login(self, path: str) -> bool:
        public_paths = {"/", "/index.html", "/landing", "/home", "/commercial", "/login", "/register", "/account", "/admin/login", "/api/account", "/api/login", "/api/admin/login", "/api/register", "/api/logout", "/api/status"}
        if path in public_paths:
            return False
        if path.startswith("/assets/") or path.startswith("/static/"):
            return False
        return path in {"/app", "/market-radar", "/research", "/longhubang", "/rps", "/simulation", "/ranking", "/admin", "/recharge"} or path.startswith("/api/")

    def _redirect(self, location: str) -> None:
        self.send_response(302)
        self.send_header("Location", location)
        self.end_headers()

    def _send_asset(self, path: str) -> None:
        prefix = "/assets/" if path.startswith("/assets/") else "/static/"
        rel = urllib.parse.unquote(path.removeprefix(prefix)).replace("\\", "/")
        if "/" in rel or rel.startswith("."):
            self.send_error(404)
            return
        fallback_map = {
            "rabbit-avatar.png": "app-icon.svg",
            "rabbit-avatar@2x.png": "app-icon.svg",
            "home-hero-rabbit-v2.png": "home-hero.png",
            "home-hero-rabbit.png": "home-hero.png",
            "home-final-v77.png": "home-hero.png",
            "rabbit-home-mascot.png": "home-hero.png",
        }
        file_path = ASSETS_DIR / rel
        if not file_path.is_file():
            fallback = fallback_map.get(rel)
            if fallback:
                file_path = ASSETS_DIR / fallback
        if not file_path.is_file():
            self.send_error(404)
            return
        data = file_path.read_bytes()
        content_type = mimetypes.guess_type(str(file_path))[0] or "application/octet-stream"
        if content_type in {"text/css", "application/javascript", "text/javascript"}:
            content_type += "; charset=utf-8"
        self.send_response(200)
        self.send_header("Content-Type", content_type)
        self.send_header("Cache-Control", "public, max-age=3600")
        self.send_header("Content-Length", str(len(data)))
        self.end_headers()
        self.wfile.write(data)

