def _save_auto_t_state(email: str | None, state: dict) -> None:
    path = user_data_path(email, "auto_t_state.json")
    path.parent.mkdir(parents=True, exist_ok=True)
    daily_backup(path)
    temp = path.with_suffix(path.suffix + ".tmp")
    temp.write_text(json.dumps(state, ensure_ascii=False, indent=2), encoding="utf-8")
    temp.replace(path)


def _auto_t_signal(row: dict) -> tuple[str, str]:
    """Select one confirmed deterministic signal. No AI call runs in the quote loop."""
    smart_t = row.get("smartT") if isinstance(row.get("smartT"), dict) else {}
    if not smart_t.get("confirmed"):
        return "", ""
    quote_time = str(row.get("time") or "")[:5]
    opening = row.get("opening") if isinstance(row.get("opening"), dict) else {}
    reminder = row.get("intradayReminder") if isinstance(row.get("intradayReminder"), dict) else {}
    if quote_time and quote_time <= "10:00" and opening.get("actionable") and opening.get("tone") in {"buy", "sell"}:
        return str(opening.get("tone")), str(opening.get("label") or opening.get("finalLabel") or "早盘确认")
    if reminder.get("actionable") and reminder.get("tone") in {"buy", "sell"}:
        return str(reminder.get("tone")), str(reminder.get("label") or "盘中确认")
    if row.get("strictSignal"):
        signal = str(row.get("signal") or "")
        if any(word in signal for word in ("低吸", "买入", "超卖", "局部低点")):
            return "buy", signal
        if any(word in signal for word in ("高抛", "卖出", "超买", "局部顶部")):
            return "sell", signal
    return "", ""


def _auto_t_owner(email: str | None) -> str:
    normalized = str(email or "").strip().lower()
    try:
        user = (load_users().get("users") or {}).get(normalized) or {}
        nickname = public_user(user).get("nickname") if user else ""
        if nickname:
            return str(nickname)
    except Exception:
        pass
    digest = hashlib.sha256(normalized.encode("utf-8")).hexdigest()[:4] if normalized else "0001"
    return f"兔友{digest.upper()}"


def _auto_t_owner_avatar(email: str | None) -> int:
    normalized = str(email or "").strip().lower()
    try:
        user = (load_users().get("users") or {}).get(normalized) or {}
        return clamp_int(user.get("avatar"), 1, 1, 10)
    except Exception:
        return 1


def _auto_t_summary(state: dict) -> dict:
    cash = round(_auto_t_number(state.get("cash"), AUTO_T_INITIAL_CASH), 2)
    positions = state.get("positions") if isinstance(state.get("positions"), dict) else {}
    market_value = round(sum(
        max(0, int(_auto_t_number(position.get("shares")))) * _auto_t_number(position.get("lastPrice"))
        for position in positions.values() if isinstance(position, dict)
    ), 2)
    total_assets = round(cash + market_value, 2)
    pnl = round(total_assets - AUTO_T_INITIAL_CASH, 2)
    return {
        "owner": str(state.get("owner") or "兔友"),
        "avatar": clamp_int(state.get("ownerAvatar"), 1, 1, 10),
        "initialCash": AUTO_T_INITIAL_CASH,
        "cash": cash,
        "marketValue": market_value,
        "totalAssets": total_assets,
        "pnl": pnl,
        "pnlPct": round(pnl / AUTO_T_INITIAL_CASH * 100, 2),
        "holdingCount": sum(1 for position in positions.values() if isinstance(position, dict) and _auto_t_number(position.get("shares")) > 0),
        "tradeCount": len(state.get("trades") or []),
        "dailyTradeCount": int(_auto_t_number(state.get("dailyTradeCount"))),
        "maxDailyTrades": AUTO_T_MAX_TRADES_PER_DAY,
        "totalFees": round(_auto_t_number(state.get("totalFees")), 2),
        "lastAction": str(state.get("lastAction") or "持仓观察"),
        "updatedAt": str(state.get("updatedAt") or ""),
    }


def _pair_trade_cycles(trades: list[dict]) -> tuple[list[dict], list[dict]]:
    """FIFO-pair opposite paper trades, including proportional transaction fees."""
    open_lots: list[dict] = []
    cycles: list[dict] = []
    for raw in trades:
        side = str(raw.get("side") or "")
        shares = max(0, int(_auto_t_number(raw.get("shares"))))
        if side not in {"buy", "sell"} or shares <= 0:
            continue
        incoming = dict(raw)
        incoming["remaining"] = shares
        incoming["feePerShare"] = _auto_t_number(raw.get("fee")) / shares
        while incoming["remaining"] > 0 and open_lots and open_lots[0]["side"] != side:
            opened = open_lots[0]
            paired = min(int(opened["remaining"]), int(incoming["remaining"]))
            buy_price = _auto_t_number(opened.get("price")) if opened["side"] == "buy" else _auto_t_number(incoming.get("price"))
            sell_price = _auto_t_number(opened.get("price")) if opened["side"] == "sell" else _auto_t_number(incoming.get("price"))
            gross = (sell_price - buy_price) * paired
            fees = (_auto_t_number(opened.get("feePerShare")) + _auto_t_number(incoming.get("feePerShare"))) * paired
            base = max(buy_price * paired, 1e-9)
            cycles.append({
                "code": str(raw.get("code") or opened.get("code") or ""),
                "name": str(raw.get("name") or opened.get("name") or ""),
                "direction": "BUY_FIRST" if opened["side"] == "buy" else "SELL_FIRST",
                "openTime": str(opened.get("time") or ""),
                "closeTime": str(incoming.get("time") or ""),
                "shares": paired,
                "buyPrice": round(buy_price, 4),
                "sellPrice": round(sell_price, 4),
                "gross": round(gross, 2),
                "fees": round(fees, 2),
                "net": round(gross - fees, 2),
                "spreadPct": round(gross / base * 100.0, 3),
            })
            opened["remaining"] -= paired
            incoming["remaining"] -= paired
            if opened["remaining"] <= 0:
                open_lots.pop(0)
        if incoming["remaining"] > 0:
            open_lots.append(incoming)
    return cycles, open_lots


def _auto_t_public_for_stock(state: dict, code: str) -> dict:
    summary = _auto_t_summary(state)
    positions = state.get("positions") if isinstance(state.get("positions"), dict) else {}
    position = positions.get(code) if isinstance(positions.get(code), dict) else {}
    today = datetime.now().strftime("%Y-%m-%d")
    stock_trades = [
        item for item in list(state.get("trades") or [])
        if isinstance(item, dict) and item.get("code") == code and item.get("date") == today
    ]
    bought_shares = sum(max(0, int(_auto_t_number(item.get("shares")))) for item in stock_trades if item.get("side") == "buy")
    sold_shares = sum(max(0, int(_auto_t_number(item.get("shares")))) for item in stock_trades if item.get("side") == "sell")
    today_fees = round(sum(_auto_t_number(item.get("fee")) for item in stock_trades), 2)
    paired_cycles, open_lots = _pair_trade_cycles(stock_trades)
    current_shares = max(0, int(_auto_t_number(position.get("shares"))))
    base_shares = max(0, int(_auto_t_number((state.get("dailyBaseShares") or {}).get(code), current_shares)))
    position_delta = current_shares - base_shares
    restore_side = "sell" if position_delta > 0 else "buy" if position_delta < 0 else ""
    restore_shares = abs(position_delta)
    last_price = _auto_t_number(position.get("lastPrice"))
    latest_trade = stock_trades[-1] if stock_trades else {}
    reference_price = _auto_t_number(latest_trade.get("price"))
    unfinished_pnl = 0.0
    if restore_shares and reference_price > 0 and last_price > 0:
        gross_open = (last_price - reference_price) * restore_shares if position_delta > 0 else (reference_price - last_price) * restore_shares
        unfinished_pnl = round(gross_open - _auto_t_number(latest_trade.get("fee")), 2)
    realized_t = round(_auto_t_number((state.get("dailyRealizedT") or {}).get(code)), 2)
    last_audit = next((item for item in reversed(list(state.get("decisionAudit") or [])) if isinstance(item, dict) and item.get("code") == code), {})
    lifecycle_map = {
        "READY": "已确认",
        "EXECUTED": "已成交",
        "DUPLICATE": "已提醒",
        "NO_ACTION": "观察",
        "WAIT_CONFIRMATION": "等待确认",
        "AUCTION_WAIT_CONFIRMATION": "等待确认",
    }
    lifecycle = "已完成配对" if stock_trades and restore_shares == 0 else lifecycle_map.get(str(last_audit.get("state") or ""), "观察")
    summary.update({
        "code": code,
        "name": str(position.get("name") or code),
        "shares": current_shares,
        "avgCost": round(_auto_t_number(position.get("avgCost")), 3),
        "lastPrice": round(_auto_t_number(position.get("lastPrice")), 3),
        "positionValue": round(max(0, int(_auto_t_number(position.get("shares")))) * _auto_t_number(position.get("lastPrice")), 2),
        "dailyCycleCount": int(_auto_t_number((state.get("dailyCycleCounts") or {}).get(code))),
        "dailyRealizedT": round(_auto_t_number((state.get("dailyRealizedT") or {}).get(code)), 2),
        "dailyBoughtShares": bought_shares,
        "dailySoldShares": sold_shares,
        "pendingBuybackShares": max(0, -position_delta),
        "extraBoughtShares": max(0, position_delta),
        "baseShares": base_shares,
        "positionDelta": position_delta,
        "restoreSide": restore_side,
        "restoreShares": restore_shares,
        "todayFees": today_fees,
        "completedNetPnl": realized_t,
        "unfinishedPnl": unfinished_pnl,
        "estimatedTotalPnl": round(realized_t + unfinished_pnl, 2),
        "pairedShares": min(bought_shares, sold_shares),
        "completedCycles": len(paired_cycles),
        "cycleDetails": paired_cycles[-12:],
        "openLots": [{key: value for key, value in item.items() if key not in {"feePerShare"}} for item in open_lots[-8:]],
        "lifecycle": lifecycle,
        "closeRisk": bool(restore_shares and datetime.now().time() >= time(14, 45)),
        "dailyLossLocked": _auto_t_number((state.get("dailyRealizedT") or {}).get(code)) <= -AUTO_T_DAILY_LOSS_LIMIT,
        "decisionAudit": [item for item in list(state.get("decisionAudit") or []) if isinstance(item, dict) and item.get("code") == code][-24:],
        "trades": [item for item in list(state.get("trades") or []) if isinstance(item, dict) and item.get("code") == code][-40:],
        "marks": [item for item in list(state.get("marks") or []) if isinstance(item, dict) and item.get("code") == code][-40:],
    })
    return summary


def _auto_t_record_decision(
    state: dict,
    row: dict,
    *,
    now: datetime,
    today: str,
    execution_state: str,
    execution_reason: str,
    executed: bool,
) -> None:
    """Keep a compact execution audit; unchanged states repeat at most every 15 minutes."""
    code = str(row.get("code") or "").strip()
    if not code:
        return
    smart_t = row.get("smartT") if isinstance(row.get("smartT"), dict) else {}
    profile = smart_t.get("profile") if isinstance(smart_t.get("profile"), dict) else {}
    key = ":".join((
        today,
        code,
        execution_state,
        str(smart_t.get("direction") or ""),
        "1" if executed else "0",
    ))
    keys = state.setdefault("lastDecisionKeys", {})
    times = state.setdefault("lastDecisionTimes", {})
    last_time = _auto_t_number(times.get(code))
    if keys.get(code) == key and now.timestamp() - last_time < 15 * 60:
        return
    item = {
        "date": today,
        "time": str(row.get("time") or now.strftime("%H:%M"))[:5],
        "code": code,
        "name": str(row.get("name") or code),
        "price": round(_auto_t_number(row.get("price")), 3),
        "state": execution_state,
        "reason": execution_reason,
        "executed": bool(executed),
        "profile": str(profile.get("name") or "balanced"),
        "profileLabel": str(profile.get("label") or "平衡"),
        "regime": str(smart_t.get("regime") or "OBSERVE"),
        "direction": str(smart_t.get("direction") or ""),
        "auctionState": str((row.get("auctionRadar") or {}).get("state") or smart_t.get("auctionState") or ""),
        "auctionDirection": str((row.get("auctionRadar") or {}).get("preferredDirection") or smart_t.get("auctionDirection") or ""),
        "auctionReason": str((row.get("auctionRadar") or {}).get("reason") or ""),
        "auctionConfirmationCount": int(_auto_t_number((row.get("auctionRadar") or {}).get("confirmationCount"))),
        "score": int(_auto_t_number(smart_t.get("score"))),
        "availableSpreadPct": round(_auto_t_number(smart_t.get("availableSpreadPct")), 3),
        "requiredGrossSpreadPct": round(_auto_t_number(smart_t.get("requiredGrossSpreadPct")), 3),
        "dailyCycleCount": int(_auto_t_number((state.get("dailyCycleCounts") or {}).get(code))),
        "dailyRealizedT": round(_auto_t_number((state.get("dailyRealizedT") or {}).get(code)), 2),
    }
    audit = state.setdefault("decisionAudit", [])
    audit.append(item)
    state["decisionAudit"] = audit[-300:]
    keys[code] = key
    times[code] = int(now.timestamp())


def smart_t_review_payload(email: str | None = None) -> dict:
    state = _load_auto_t_state(email)
    today = datetime.now().strftime("%Y-%m-%d")
    items = [item for item in list(state.get("decisionAudit") or []) if isinstance(item, dict) and item.get("date") == today]
    trades = [item for item in list(state.get("trades") or []) if isinstance(item, dict) and item.get("date") == today]
    cycles, open_lots = _pair_trade_cycles(trades)
    gross_pnl = round(sum(_auto_t_number(item.get("gross")) for item in cycles), 2)
    cycle_fees = round(sum(_auto_t_number(item.get("fees")) for item in cycles), 2)
    net_pnl = round(sum(_auto_t_number(item.get("net")) for item in cycles), 2)
    all_fees = round(sum(_auto_t_number(item.get("fee")) for item in trades), 2)
    wins = sum(1 for item in cycles if _auto_t_number(item.get("net")) > 0)
    losses = sum(1 for item in cycles if _auto_t_number(item.get("net")) <= 0)
    average_spread = round(sum(_auto_t_number(item.get("spreadPct")) for item in cycles) / len(cycles), 3) if cycles else 0.0
    positions = state.get("positions") if isinstance(state.get("positions"), dict) else {}
    base_shares = state.get("dailyBaseShares") if isinstance(state.get("dailyBaseShares"), dict) else {}
    position_risks = []
    for code, position in positions.items():
        if not isinstance(position, dict):
            continue
        shares = max(0, int(_auto_t_number(position.get("shares"))))
        base = max(0, int(_auto_t_number(base_shares.get(code), shares)))
        delta = shares - base
        if delta:
            position_risks.append({
                "code": code,
                "name": str(position.get("name") or code),
                "deltaShares": delta,
                "action": "卖出" if delta > 0 else "买回",
                "shares": abs(delta),
            })
    blocked: dict[str, int] = {}
    for item in items:
        if not item.get("executed"):
            key = str(item.get("state") or "WAIT")
            blocked[key] = blocked.get(key, 0) + 1
    blocked_rows = [{"state": key, "count": value} for key, value in sorted(blocked.items(), key=lambda pair: pair[1], reverse=True)]
    is_today = state.get("dailyTradeDate") == today
    cycle_counts = state.get("dailyCycleCounts") if is_today and isinstance(state.get("dailyCycleCounts"), dict) else {}
    realized = state.get("dailyRealizedT") if is_today and isinstance(state.get("dailyRealizedT"), dict) else {}
    return {
        "date": today,
        "decisionCount": len(items),
        "executedCount": sum(1 for item in items if item.get("executed")),
        "tradeCount": len(trades),
        "cycleCount": sum(int(_auto_t_number(value)) for value in cycle_counts.values()),
        "realizedT": round(sum(_auto_t_number(value) for value in realized.values()), 2),
        "completedCycles": len(cycles),
        "wins": wins,
        "losses": losses,
        "winRate": round(wins / len(cycles) * 100.0, 1) if cycles else 0.0,
        "grossPnl": gross_pnl,
        "fees": all_fees,
        "pairedFees": cycle_fees,
        "netPnl": net_pnl,
        "averageSpreadPct": average_spread,
        "feeToGrossPct": round(all_fees / gross_pnl * 100.0, 1) if gross_pnl > 0 else 0.0,
        "positionRisks": position_risks,
        "openLotCount": len(open_lots),
        "cycles": cycles[-30:][::-1],
        "blocked": blocked_rows[:8],
        "items": items[-40:][::-1],
    }


def _auto_t_leaderboard() -> list[dict]:
    ranking: list[dict] = []
    paths = list(USER_DATA_DIR.glob("*_auto_t_state.json")) if USER_DATA_DIR.exists() else []
    default_path = BASE_DIR / "auto_t_state.json"
    if default_path.is_file():
        paths.append(default_path)
    seen: set[str] = set()
    for path in paths:
        try:
            state = json.loads(path.read_text(encoding="utf-8"))
            if not isinstance(state, dict) or state.get("version") != 2:
                continue
            item = _auto_t_summary(state)
            owner_key = str(state.get("ownerId") or path.name)
            if owner_key in seen:
                continue
            seen.add(owner_key)
            ranking.append(item)
        except Exception:
            continue
    ranking.sort(key=lambda item: (item.get("totalAssets", 0), item.get("pnl", 0)), reverse=True)
    for index, item in enumerate(ranking, 1):
        item["rank"] = index
    return ranking


def auto_t_update(rows: list[dict], email: str | None = None) -> list[dict]:
    """Advance one shared 100k paper portfolio for the signed-in member."""
    now = datetime.now()
    today = now.strftime("%Y-%m-%d")
    with AUTO_T_STATE_LOCK:
        state = _load_auto_t_state(email)
        normalized_email = str(email or "").strip().lower()
        state["owner"] = _auto_t_owner(email)
        state["ownerAvatar"] = _auto_t_owner_avatar(email)
        state["ownerId"] = hashlib.sha256(normalized_email.encode("utf-8")).hexdigest()[:16] if normalized_email else "local"
        positions = state.setdefault("positions", {})
        trades = state.setdefault("trades", [])
        marks = state.setdefault("marks", [])
        signal_keys = state.setdefault("lastSignalKeys", {})
        trade_times = state.setdefault("lastTradeTimes", {})
        if state.get("dailyTradeDate") != today:
            state["dailyTradeDate"] = today
            state["dailyTradeCount"] = 0
            state["dailyTradeSides"] = {}
            state["dailyReferencePrices"] = {}
            state["dailyReferenceFees"] = {}
            state["dailyReferenceShares"] = {}
            state["dailyBaseShares"] = {}
            state["dailyCycleCounts"] = {}
            state["dailyRealizedT"] = {}
        daily_sides = state.setdefault("dailyTradeSides", {})
        daily_reference_prices = state.setdefault("dailyReferencePrices", {})
        daily_reference_fees = state.setdefault("dailyReferenceFees", {})
        daily_reference_shares = state.setdefault("dailyReferenceShares", {})
        daily_base_shares = state.setdefault("dailyBaseShares", {})
        daily_cycle_counts = state.setdefault("dailyCycleCounts", {})
        daily_realized_t = state.setdefault("dailyRealizedT", {})
        changed = False

        valid_rows = [row for row in rows if str(row.get("code") or "").strip() and _auto_t_number(row.get("price")) > 0]
        if not positions and valid_rows:
            per_stock_budget = AUTO_T_INITIAL_CASH * 0.5 / len(valid_rows)
            invested = 0.0
            for row in valid_rows:
                code = str(row.get("code") or "").strip()
                price = _auto_t_number(row.get("price"))
                shares = max(0, int(per_stock_budget // (price * 100)) * 100)
                cost = round(shares * price, 2)
                positions[code] = {"name": str(row.get("name") or code), "shares": shares, "avgCost": round(price, 4), "lastPrice": price}
                invested += cost
            state["cash"] = round(AUTO_T_INITIAL_CASH - invested, 2)
            state["lastAction"] = "初始约半仓，保留现金做T"
            changed = True

        for row in rows:
            code = str(row.get("code") or "").strip()
            price = _auto_t_number(row.get("price"))
            if not code or price <= 0:
                continue
            position = positions.setdefault(code, {"name": str(row.get("name") or code), "shares": 0, "avgCost": 0, "lastPrice": price})
            position["name"] = str(row.get("name") or position.get("name") or code)
            position["lastPrice"] = price
            daily_base_shares.setdefault(code, max(0, int(_auto_t_number(position.get("shares")))))

            reminder = row.get("intradayReminder") if isinstance(row.get("intradayReminder"), dict) else {}
            reminder_label = str(reminder.get("label") or "")
            if "超买" in reminder_label or "超卖" in reminder_label:
                mark_type = "overbought" if "超买" in reminder_label else "oversold"
                mark_time = str(row.get("time") or "--:--")[:5]
                mark_key = f"{today}:{code}:{mark_time}:{mark_type}"
                if not any(str(item.get("key")) == mark_key for item in marks[-80:] if isinstance(item, dict)):
                    marks.append({"key": mark_key, "code": code, "time": mark_time, "type": mark_type, "price": round(price, 3), "label": reminder_label})
                    state["marks"] = marks[-200:]
                    changed = True

            smart_t = row.get("smartT") if isinstance(row.get("smartT"), dict) else {}
            profile = smart_t.get("profile") if isinstance(smart_t.get("profile"), dict) else {}
            current_shares = max(0, int(_auto_t_number(position.get("shares"))))
            base_shares = max(0, int(_auto_t_number(daily_base_shares.get(code), current_shares)))
            open_cycle = current_shares != base_shares
            force_close = bool(smart_t.get("forceClose")) and open_cycle
            if force_close:
                side = "sell" if current_shares > base_shares else "buy"
                reason = "14:50后恢复T仓到日内基准持仓"
            else:
                side, reason = _auto_t_signal(row)
            market_open = str(row.get("marketStatus") or "") == "交易中"
            quote_valid = not bool(row.get("quoteStale"))
            quote_time = str(row.get("time") or "--:--")[:5]
            signal_key = f"{today}:{quote_time}:{side}:{reason}"
            last_side = str(daily_sides.get(code) or "")
            reference_price = _auto_t_number(daily_reference_prices.get(code))
            cooldown_seconds = max(60, int(_auto_t_number(profile.get("cooldown_minutes"), AUTO_T_COOLDOWN_SECONDS / 60)) * 60)
            max_daily_cycles = max(1, int(_auto_t_number(profile.get("max_daily_cycles"), 3)))
            cooldown_ok = force_close or now.timestamp() - _auto_t_number(trade_times.get(code)) >= cooldown_seconds
            daily_limit_ok = open_cycle or int(_auto_t_number(daily_cycle_counts.get(code))) < max_daily_cycles
            loss_lock = _auto_t_number(daily_realized_t.get(code)) <= -AUTO_T_DAILY_LOSS_LIMIT
            loss_ok = open_cycle or not loss_lock
            alternating_ok = not last_side or last_side != side
            edge_ok = True
            if force_close:
                edge_ok = True
            elif side == "buy" and last_side == "sell" and reference_price > 0:
                edge_ok = price <= reference_price * (1 - AUTO_T_MIN_EDGE_RATE)
            elif side == "sell" and last_side == "buy" and reference_price > 0:
                edge_ok = price >= reference_price * (1 + AUTO_T_MIN_EDGE_RATE)
            elif side == "sell" and _auto_t_number(position.get("avgCost")) > 0:
                edge_ok = price >= _auto_t_number(position.get("avgCost")) * (1 + AUTO_T_MIN_EDGE_RATE)
            executed = False
            if not smart_t.get("confirmed") and not force_close:
                execution_state = str(smart_t.get("state") or "WAIT_CONFIRMATION")
                execution_reason = str(smart_t.get("reason") or "等待确定性信号确认。")
            elif not side:
                execution_state, execution_reason = "NO_ACTION", "信号方向不明确，保持观察。"
            elif not market_open:
                execution_state, execution_reason = "MARKET_CLOSED", "当前不在连续竞价时段。"
            elif not quote_valid:
                execution_state, execution_reason = "DATA_RISK", "行情数据延迟，暂停执行。"
            elif signal_key == signal_keys.get(code):
                execution_state, execution_reason = "DUPLICATE", "相同信号已经处理，不重复成交。"
            elif not cooldown_ok:
                execution_state, execution_reason = "COOLDOWN", f"距离上一笔不足{max(1, cooldown_seconds // 60)}分钟，等待冷却。"
            elif not daily_limit_ok:
                execution_state, execution_reason = "DAILY_LIMIT", f"已达到{max_daily_cycles}轮日内上限。"
            elif not loss_ok:
                execution_state, execution_reason = "LOSS_LOCKED", f"日内做T亏损达到保护线{-AUTO_T_DAILY_LOSS_LIMIT:.0f}元，停止新循环。"
            elif not alternating_ok:
                execution_state, execution_reason = "SIDE_LOCKED", "同方向动作不连续执行，等待反向完成循环。"
            elif not edge_ok:
                execution_state, execution_reason = "EDGE_BLOCKED", "当前价差不足以覆盖交易成本与安全垫。"
            else:
                execution_state, execution_reason = ("FORCE_CLOSE_READY", "准备恢复日内基准仓位。") if force_close else ("READY", str(smart_t.get("reason") or reason or "满足执行条件。"))
            if side and market_open and quote_valid and signal_key != signal_keys.get(code) and cooldown_ok and daily_limit_ok and loss_ok and alternating_ok and edge_ok:
                restoring_base = open_cycle and ((current_shares > base_shares and side == "sell") or (current_shares < base_shares and side == "buy"))
                lot_shares = abs(current_shares - base_shares) if restoring_base else max(100, int(AUTO_T_TRADE_BUDGET // (price * 100)) * 100)
                cash = _auto_t_number(state.get("cash"), AUTO_T_INITIAL_CASH)
                shares = max(0, int(_auto_t_number(position.get("shares"))))
                trade_shares = 0
                amount = 0.0
                fee = 0.0
                if side == "buy":
                    trade_shares = min(lot_shares, max(0, int(max(0, cash - AUTO_T_MIN_COMMISSION) // (price * 100)) * 100))
                    while trade_shares > 0:
                        amount = round(trade_shares * price, 2)
                        fee = _auto_t_trade_fee(side, amount)
                        if amount + fee <= cash:
                            break
                        trade_shares -= 100
                    if trade_shares > 0:
                        old_cost = _auto_t_number(position.get("avgCost")) * shares
                        state["cash"] = round(cash - amount - fee, 2)
                        position["shares"] = shares + trade_shares
                        position["avgCost"] = round((old_cost + amount + fee) / max(1, shares + trade_shares), 4)
                else:
                    trade_shares = min(lot_shares, shares)
                    if trade_shares > 0:
                        amount = round(trade_shares * price, 2)
                        fee = _auto_t_trade_fee(side, amount)
                        state["cash"] = round(cash + amount - fee, 2)
                        position["shares"] = shares - trade_shares
                if trade_shares > 0:
                    executed = True
                    execution_state = "EXECUTED"
                    execution_reason = reason or ("恢复日内基准仓位。" if force_close else "Smart-T条件满足并完成模拟成交。")
                    completed_cycle = bool(last_side) and last_side != side
                    reference_shares = max(0, int(_auto_t_number(daily_reference_shares.get(code), trade_shares)))
                    paired_shares = min(trade_shares, reference_shares)
                    cycle_net = 0.0
                    if completed_cycle and reference_price > 0 and paired_shares > 0:
                        gross = (price - reference_price) * paired_shares if last_side == "buy" else (reference_price - price) * paired_shares
                        cycle_net = round(gross - _auto_t_number(daily_reference_fees.get(code)) - fee, 2)
                    trade = {
                        "code": code,
                        "name": str(row.get("name") or code),
                        "time": quote_time,
                        "date": today,
                        "side": side,
                        "price": round(price, 3),
                        "shares": trade_shares,
                        "amount": round(trade_shares * price, 2),
                        "fee": fee,
                        "reason": reason,
                    }
                    trades.append(trade)
                    state["trades"] = trades[-300:]
                    signal_keys[code] = signal_key
                    trade_times[code] = int(now.timestamp())
                    daily_sides[code] = side
                    daily_reference_prices[code] = price
                    daily_reference_fees[code] = fee
                    daily_reference_shares[code] = trade_shares
                    if completed_cycle:
                        daily_cycle_counts[code] = int(_auto_t_number(daily_cycle_counts.get(code))) + 1
                        daily_realized_t[code] = round(_auto_t_number(daily_realized_t.get(code)) + cycle_net, 2)
                    state["dailyTradeCount"] = int(_auto_t_number(state.get("dailyTradeCount"))) + 1
                    state["totalFees"] = round(_auto_t_number(state.get("totalFees")) + fee, 2)
                    state["lastAction"] = f"{row.get('name') or code} {'买入' if side == 'buy' else '卖出'} {trade_shares}股 @ {price:.2f}，费用{fee:.2f}"
                    changed = True
                else:
                    execution_state, execution_reason = "CAPACITY_BLOCKED", "可用现金或可卖持仓不足，未执行。"
            _auto_t_record_decision(
                state,
                row,
                now=now,
                today=today,
                execution_state=execution_state,
                execution_reason=execution_reason,
                executed=executed,
            )

        state["updatedAt"] = now.isoformat(timespec="seconds")
        state["initialCash"] = AUTO_T_INITIAL_CASH
        if changed or rows:
            try:
                _save_auto_t_state(email, state)
            except Exception:
                pass
        for row in rows:
            code = str(row.get("code") or "").strip()
            if code:
                row["paperT"] = _auto_t_public_for_stock(state, code)
        return _auto_t_leaderboard()


def auto_t_ranking_payload(email: str | None = None) -> dict:
    with AUTO_T_STATE_LOCK:
        ranking = _auto_t_leaderboard()
    return {
        "ok": True,
        "initialCash": AUTO_T_INITIAL_CASH,
        "updatedAt": datetime.now().strftime("%m-%d %H:%M:%S"),
        "ranking": ranking,
        "message": "每位会员共用10万元模拟总资产，单笔最多动用约2万元，按总资产从高到低排名。",
    }


def load_dashboard_settings(email: str | None = None) -> dict:
    defaults = {"cash": 100000, "trade": 20000, "sample": 10, "days": 5}
    data = read_dashboard_settings_file(email)
    settings = {
        "cash": clamp_int(data.get("cash"), defaults["cash"], 1000, 100000000),
        "trade": clamp_int(data.get("trade"), defaults["trade"], 1000, 100000000),
        "sample": clamp_int(data.get("sample"), defaults["sample"], 1, 30),
        "days": clamp_int(data.get("days"), defaults["days"], 1, 60),
    }
    settings.update(public_extra_settings(data))
    settings.update(load_profit_strategy_settings(email))
    settings.update(public_ai_settings(data))
    return {"ok": True, **settings}


def save_dashboard_settings(data: dict, email: str | None = None) -> dict:
    current = read_dashboard_settings_file(email)
    settings = dict(current)
    settings.update({
        "cash": clamp_int(data.get("cash"), 100000, 1000, 100000000),
        "trade": clamp_int(data.get("trade"), 20000, 1000, 100000000),
        "sample": clamp_int(data.get("sample"), 10, 1, 30),
        "days": clamp_int(data.get("days"), 5, 1, 60),
    })
    settings.update(sanitize_extra_settings(data, current))
    settings.update(sanitize_ai_settings(data, current))
    try:
        settings_path = user_data_path(email, "dashboard_settings.json")
        daily_backup(settings_path)
        temp = settings_path.with_suffix(settings_path.suffix + ".tmp")
        temp.write_text(json.dumps(settings, ensure_ascii=False, indent=2), encoding="utf-8")
        temp.replace(settings_path)
    except Exception:
        out = {"cash": settings["cash"], "trade": settings["trade"], "sample": settings["sample"], "days": settings["days"]}
        out.update(public_ai_settings(settings))
        return {"ok": False, **out}
    save_strategy_options(data, email)
    out = {"cash": settings["cash"], "trade": settings["trade"], "sample": settings["sample"], "days": settings["days"]}
    out.update(load_profit_strategy_settings(email))
    out.update(public_extra_settings(settings))
    out.update(load_profit_strategy_settings(email))
    out.update(public_ai_settings(settings))
    return {"ok": True, **out}


def sanitize_extra_settings(data: dict, current: dict) -> dict:
    keep = {}
    text_fields = {
        "marketDataApi": 220,
        "newsApi": 220,
        "quoteApi": 220,
        "customStrategy": 2200,
        "strategyMode": 32,
        "maxSignalsPerDay": 8,
        "lowBuyDev": 12,
        "highSellDev": 12,
        "signalCooldown": 8,
    }
    for key, limit in text_fields.items():
        if key in data:
            keep[key] = str(data.get(key) or "").strip()[:limit]
        elif key in current:
            keep[key] = str(current.get(key) or "").strip()[:limit]
    return keep


def public_extra_settings(data: dict) -> dict:
    return {
        "marketDataApi": str(data.get("marketDataApi") or ""),
        "newsApi": str(data.get("newsApi") or ""),
        "quoteApi": str(data.get("quoteApi") or ""),
        "customStrategy": str(data.get("customStrategy") or ""),
        "strategyMode": str(data.get("strategyMode") or "官方默认策略"),
        "maxSignalsPerDay": str(data.get("maxSignalsPerDay") or "2"),
        "lowBuyDev": str(data.get("lowBuyDev") or "-1.20"),
        "highSellDev": str(data.get("highSellDev") or "1.40"),
        "signalCooldown": str(data.get("signalCooldown") or "10"),
    }


def read_dashboard_settings_file(email: str | None = None) -> dict:
    path = user_data_path(email, "dashboard_settings.json")
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}


def sanitize_ai_settings(data: dict, current: dict) -> dict:
    provider = str(data.get("aiProvider") or current.get("aiProvider") or "ChatGPT").strip()
    provider_alias = {
        "OpenAI": "ChatGPT",
        "OpenAI兼容": "ThirdParty",
        "OpenAI Compatible": "ThirdParty",
        "OpenAICompatible": "ThirdParty",
        "第三方API": "ThirdParty",
    }
    provider = provider_alias.get(provider, provider)
    if provider not in {"ChatGPT", "Gemini", "Claude", "ThirdParty"}:
        provider = "ChatGPT"
    model_default = {"ChatGPT": "gpt-4o-mini", "Gemini": "gemini-2.5-flash", "Claude": "claude-sonnet-4", "ThirdParty": "gpt-4o-mini"}[provider]
    ai = {
        "aiProvider": provider,
        "aiModel": str(data.get("aiModel") or current.get("aiModel") or model_default).strip()[:80],
        "aiBase": str(data.get("aiBase") or current.get("aiBase") or "").strip()[:220],
        "aiProxy": str(data.get("aiProxy") or current.get("aiProxy") or "").strip()[:220],
    }
    if data.get("aiClearKey"):
        ai["aiKey"] = ""
    else:
        raw_key = str(data.get("aiKey") or "").strip()
        ai["aiKey"] = raw_key if raw_key and not raw_key.startswith("已配置") else str(current.get("aiKey") or "").strip()
    return ai


def public_ai_settings(data: dict) -> dict:
    key = str(data.get("aiKey") or "").strip()
    fallback_key = ""
    if not key:
        for name in ("GEMINI_API_KEY", "GOOGLE_API_KEY"):
            fallback_key = os.environ.get(name, "").strip()
            if fallback_key:
                break
        if not fallback_key:
            env = load_desktop_env()
            fallback_key = env.get("GEMINI_API_KEY") or env.get("GOOGLE_API_KEY") or env.get("API_KEY") or ""
    provider = str(data.get("aiProvider") or "ChatGPT")
    provider = {"OpenAI": "ChatGPT", "OpenAI Compatible": "ThirdParty", "OpenAI兼容": "ThirdParty", "OpenAICompatible": "ThirdParty", "第三方API": "ThirdParty"}.get(provider, provider)
    if provider not in {"ChatGPT", "Gemini", "Claude", "ThirdParty"}:
        provider = "ChatGPT"
    provider_labels = {"ChatGPT": "ChatGPT", "Gemini": "Gemini", "Claude": "Claude", "ThirdParty": "第三方API"}
    model_defaults = {"ChatGPT": "gpt-4o-mini", "Gemini": "gemini-2.5-flash", "Claude": "claude-sonnet-4", "ThirdParty": "gpt-4o-mini"}
    return {
        "aiProvider": provider,
        "aiProviderLabel": provider_labels[provider],
        "aiModel": str(data.get("aiModel") or model_defaults[provider]),
        "aiBase": str(data.get("aiBase") or ""),
        "aiProxy": str(data.get("aiProxy") or ""),
        "aiKeyConfigured": bool(key or fallback_key),
        "aiKeyMasked": mask_secret(key) if key else ("已读取本机配置" if fallback_key else ""),
    }


def mask_secret(value: str) -> str:
    value = str(value or "").strip()
    if not value:
        return ""
    if len(value) <= 8:
        return "已配置"
    return f"已配置，尾号 {value[-4:]}"


def persist_rolling_cash(options: dict, stats: dict, email: str | None = None) -> None:
    ending_cash = money_to_float(stats.get("endingCash"))
    if ending_cash <= 0:
        return
    save_dashboard_settings(
        {
            "cash": ending_cash,
            "trade": options.get("trade") or money_to_float(stats.get("trade")),
            "sample": options.get("sample") or 10,
        },
        email,
    )


def load_users() -> dict:
    try:
        data = json.loads(USERS_PATH.read_text(encoding="utf-8"))
        return data if isinstance(data, dict) else {"users": {}}
    except Exception:
        return {"users": {}}


def save_users(data: dict) -> None:
    USERS_PATH.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")


def load_activation_codes() -> dict:
    try:
        data = json.loads(ACTIVATION_CODES_PATH.read_text(encoding="utf-8"))
        return data if isinstance(data, dict) else {"codes": {}, "used": {}}
    except Exception:
        return {"codes": {}, "used": {}}


def save_activation_codes(data: dict) -> None:
    ACTIVATION_CODES_PATH.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")


def activation_code_text(plan: str) -> str:
    prefix = "T99" if "永久" in str(plan) else "T9"
    middle = secrets.token_hex(3).upper()
    tail = secrets.token_hex(2).upper()
    return f"{prefix}-{middle}-{tail}"


def plan_definition(plan: str) -> dict:
    text = str(plan or "").strip().lower()
    if text in {"life", "permanent", "forever", "99", "lifetime"} or "永久" in text:
        return {"plan": "永久版", "days": 36500, "watchLimit": 200, "aiReviewLimit": 500}
    return {"plan": "月卡", "days": 31, "watchLimit": 20, "aiReviewLimit": 80}


def activation_definition(code: str, store: dict) -> dict | None:
    code = normalize_activation_code(code)
    custom = (store.get("codes") or {}).get(code)
    if isinstance(custom, dict):
        return custom
    return BUILTIN_ACTIVATION_CODES.get(code)


def normalize_activation_code(code: str) -> str:
    return re.sub(r"\s+", "", str(code or "")).upper()


def admin_activation_codes_payload() -> dict:
    store = load_activation_codes()
    codes = store.setdefault("codes", {})
    used = store.setdefault("used", {})
    rows = []
    for code, info in sorted(codes.items(), key=lambda item: str(item[1].get("createdAt") or ""), reverse=True):
        used_info = used.get(code) or {}
        rows.append({
            "code": code,
            "plan": info.get("plan", "月卡"),
            "days": info.get("days", 31),
            "createdAt": info.get("createdAt", ""),
            "createdBy": info.get("createdBy", ""),
            "status": "已使用" if used_info else "未使用",
            "redeemedBy": used_info.get("email", ""),
            "redeemedAt": used_info.get("redeemedAt", ""),
        })
    return {"ok": True, "codes": rows, "count": len(rows), "unused": sum(1 for row in rows if row["status"] == "未使用")}


def create_activation_codes_payload(email: str, data: dict) -> dict:
    plan = str(data.get("plan") or "月卡")
    count = clamp_int(data.get("count"), 1, 1, 50)
    definition = plan_definition(plan)
    store = load_activation_codes()
    codes = store.setdefault("codes", {})
    now = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    created = []
    for _ in range(count):
        code = activation_code_text(definition["plan"])
        while code in codes or code in BUILTIN_ACTIVATION_CODES:
            code = activation_code_text(definition["plan"])
        codes[code] = {
            **definition,
            "createdAt": now,
            "createdBy": email,
        }
        created.append(code)
    save_activation_codes(store)
    return {"ok": True, "message": f"已生成 {len(created)} 个{definition['plan']}激活码。", "created": created, **admin_activation_codes_payload()}


def redeem_activation_payload(email: str, data: dict) -> dict:
    if not email:
        return {"ok": False, "message": "请先登录后充值。"}
    code = normalize_activation_code(data.get("code") or "")
    if not code:
        return {"ok": False, "message": "请输入激活码。"}
    code_store = load_activation_codes()
    used = code_store.setdefault("used", {})
    if code in used and used[code].get("email") != email:
        return {"ok": False, "message": "这个激活码已经被其他账号使用。"}
    definition = activation_definition(code, code_store)
    if not definition:
        return {"ok": False, "message": "激活码无效，请核对后再试。"}
    user_store = load_users()
    user = user_store.get("users", {}).get(email)
    if not user:
        return {"ok": False, "message": "账号不存在，请重新登录。"}
    now = datetime.now()
    days = int(definition.get("days") or 31)
    plan = str(definition.get("plan") or "月卡")
    current_expire = parse_datetime(user.get("planExpireAt"))
    base = current_expire if current_expire and current_expire > now else now
    expire = base + timedelta(days=days)
    user["plan"] = plan
    user["planExpireAt"] = expire.strftime("%Y-%m-%d %H:%M:%S") if days < 30000 else "永久"
    user["watchLimit"] = int(definition.get("watchLimit") or (200 if plan == "永久版" else 20))
    user["aiReviewLimit"] = int(definition.get("aiReviewLimit") or (500 if plan == "永久版" else 80))
    user.setdefault("activationHistory", []).append({
        "code": code,
        "plan": plan,
        "redeemedAt": now.strftime("%Y-%m-%d %H:%M:%S"),
        "expireAt": user["planExpireAt"],
    })
    used[code] = {"email": email, "plan": plan, "redeemedAt": now.strftime("%Y-%m-%d %H:%M:%S")}
    save_users(user_store)
    save_activation_codes(code_store)
    return {"ok": True, "message": f"充值成功，已开通{plan}。", "account": public_user(user)}


def parse_datetime(value: object) -> datetime | None:
    text = str(value or "").strip()
    if not text or text == "永久":
        return None
    for fmt in ("%Y-%m-%d %H:%M:%S", "%Y-%m-%d"):
        try:
            return datetime.strptime(text, fmt)
        except Exception:
            pass
    return None


def legacy_hash_password(password: str, salt: str) -> str:
    return hashlib.sha256((salt + password).encode("utf-8")).hexdigest()


def hash_password(password: str, salt: str, iterations: int = 210000) -> str:
    digest = hashlib.pbkdf2_hmac("sha256", password.encode("utf-8"), salt.encode("utf-8"), iterations)
    return f"pbkdf2_sha256${iterations}${digest.hex()}"


def verify_password(password: str, user: dict) -> bool:
    stored = str(user.get("password") or "")
    salt = str(user.get("salt") or "")
    if stored.startswith("pbkdf2_sha256$"):
        try:
            _scheme, iter_text, digest = stored.split("$", 2)
            expected = hash_password(password, salt, int(iter_text))
            return hmac.compare_digest(stored, expected)
        except Exception:
            return False
    return hmac.compare_digest(stored, legacy_hash_password(password, salt))


def maybe_upgrade_password(password: str, user: dict, store: dict) -> None:
    stored = str(user.get("password") or "")
    if stored.startswith("pbkdf2_sha256$"):
        return
    user["password"] = hash_password(password, str(user.get("salt") or ""))
    save_users(store)


def ensure_admin_account() -> dict:
    env_email = str(os.environ.get("DASHBOARD_ADMIN_EMAIL") or "").strip().lower()
    env_password = str(os.environ.get("DASHBOARD_ADMIN_PASSWORD") or "")
    created = False
    if env_email and env_password:
        creds = {"email": env_email, "password": env_password, "source": "env"}
    else:
        try:
            creds = json.loads(ADMIN_CREDENTIALS_PATH.read_text(encoding="utf-8"))
        except Exception:
            creds = {}
        email = str(creds.get("email") or "admin@zhuandianmi.local").strip().lower()
        password = str(creds.get("password") or "")
        if len(password) < 10:
            password = "T" + secrets.token_urlsafe(13)
            created = True
        creds = {
            "email": email,
            "password": password,
            "createdAt": str(creds.get("createdAt") or datetime.now().strftime("%Y-%m-%d %H:%M:%S")),
            "note": "本机管理员账号。请妥善保存，勿提交到 GitHub。",
        }
        if created or not ADMIN_CREDENTIALS_PATH.exists():
            try:
                ADMIN_CREDENTIALS_PATH.write_text(json.dumps(creds, ensure_ascii=False, indent=2), encoding="utf-8")
            except Exception:
                pass
    store = load_users()
    users = store.setdefault("users", {})
    user = users.get(creds["email"])
    if not user or env_password:
        salt = secrets.token_hex(12)
        user = {
            "email": creds["email"],
            "nickname": "管理员",
            "salt": salt,
            "password": hash_password(creds["password"], salt),
            "plan": "管理员",
            "planExpireAt": "永久",
            "watchLimit": 999,
            "aiReviewLimit": 999,
            "role": "admin",
            "createdAt": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        }
        users[creds["email"]] = user
        save_users(store)
    elif str(user.get("role") or "").lower() != "admin":
        user["role"] = "admin"
        user["plan"] = user.get("plan") or "管理员"
        user["planExpireAt"] = user.get("planExpireAt") or "永久"
        save_users(store)
    return creds


def admin_login_payload(handler: Handler, data: dict) -> dict | None:
    creds = ensure_admin_account()
    email = str(data.get("email") or "").strip().lower()
    password = str(data.get("password") or "")
    if not email:
        email = str(creds.get("email") or "").strip().lower()
    throttle_key = login_throttle_key(handler, f"admin:{email}")
    blocked = login_block_seconds(throttle_key)
    if blocked > 0:
        return {"ok": False, "message": f"登录尝试过多，请 {max(1, blocked // 60)} 分钟后再试。"}
    store = load_users()
    users = store.get("users", {})
    user = users.get(email)
    if not user or str(user.get("role") or "").lower() != "admin" or not verify_password(password, user):
        record_login_failure(throttle_key)
        return {"ok": False, "message": "管理员账号或密码不正确。"}
    clear_login_failures(throttle_key)
    maybe_upgrade_password(password, user, store)
    token = create_session(email)
    handler.send_response(200)
    handler.send_header("Content-Type", "application/json; charset=utf-8")
    set_session_cookie(handler, token)
    payload = json.dumps({"ok": True, "message": "管理员登录成功。", "account": public_user(user)}, ensure_ascii=False).encode("utf-8")
    handler.send_header("Content-Length", str(len(payload)))
    handler.end_headers()
    handler.wfile.write(payload)
    return None


def login_throttle_key(handler: Handler, email: str) -> str:
    forwarded = str(handler.headers.get("X-Forwarded-For") or "").split(",", 1)[0].strip()
    ip = forwarded or (handler.client_address[0] if handler.client_address else "unknown")
    return f"{ip}|{email}"


def login_block_seconds(key: str) -> int:
    item = LOGIN_FAILURES.get(key)
    if not item:
        return 0
    now = time_mod.time()
    if item.get("lockUntil", 0) > now:
        return int(item["lockUntil"] - now)
    if now - item.get("firstAt", now) > LOGIN_WINDOW_SECONDS:
        LOGIN_FAILURES.pop(key, None)
    return 0


def record_login_failure(key: str) -> None:
    now = time_mod.time()
    item = LOGIN_FAILURES.get(key)
    if not item or now - item.get("firstAt", now) > LOGIN_WINDOW_SECONDS:
        item = {"firstAt": now, "count": 0, "lockUntil": 0}
    item["count"] = int(item.get("count", 0)) + 1
    if item["count"] >= MAX_LOGIN_FAILURES:
        item["lockUntil"] = now + LOGIN_LOCK_SECONDS
    LOGIN_FAILURES[key] = item


def clear_login_failures(key: str) -> None:
    LOGIN_FAILURES.pop(key, None)


def load_sessions() -> None:
    if SESSIONS:
        return
    try:
        data = json.loads(SESSIONS_PATH.read_text(encoding="utf-8"))
    except Exception:
        data = {}
    now = time_mod.time()
    changed = False
    for token, item in (data.get("sessions") or {}).items():
        email = str(item.get("email") or "").strip().lower()
        expires = float(item.get("expires") or 0)
        if re.fullmatch(r"[a-f0-9]{48}", str(token)) and email and expires > now:
            SESSIONS[str(token)] = email
            SESSION_EXPIRES[str(token)] = expires
        else:
            changed = True
    if changed:
        save_sessions()


def save_sessions() -> None:
    now = time_mod.time()
    payload = {"sessions": {}}
    for token, email in list(SESSIONS.items()):
        expires = float(SESSION_EXPIRES.get(token) or 0)
        if expires <= now:
            SESSIONS.pop(token, None)
            SESSION_EXPIRES.pop(token, None)
            continue
        payload["sessions"][token] = {"email": email, "expires": expires}
    try:
        SESSIONS_PATH.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception:
        pass


def create_session(email: str) -> str:
    token = secrets.token_hex(24)
    SESSIONS[token] = email
    SESSION_EXPIRES[token] = time_mod.time() + SESSION_TTL_SECONDS
    save_sessions()
    return token


def remove_session(token: str) -> None:
    SESSIONS.pop(token, None)
    SESSION_EXPIRES.pop(token, None)
    save_sessions()


def current_email(handler: Handler) -> str:
    cookie = handler.headers.get("Cookie", "")
    m = re.search(r"session=([a-f0-9]+)", cookie)
    if not m:
        return ""
    load_sessions()
    token = m.group(1)
    email = SESSIONS.get(token, "")
    if not email:
        return ""
    if SESSION_EXPIRES.get(token, 0) <= time_mod.time():
        remove_session(token)
        return ""
    return email


def set_session_cookie(handler: Handler, token: str) -> None:
    handler.send_header("Set-Cookie", f"session={token}; Path=/; Max-Age={SESSION_TTL_SECONDS}; HttpOnly; SameSite=Lax")


def register_payload(handler: Handler, data: dict) -> dict | None:
    email = str(data.get("email") or "").strip().lower()
    password = str(data.get("password") or "")
    nickname = str(data.get("nickname") or "").strip() or email.split("@")[0]
    avatar = clamp_int(data.get("avatar"), 1, 1, 10)
    if not re.match(r"^[^@\s]+@[^@\s]+\.[^@\s]+$", email):
        return {"ok": False, "message": "请输入正确邮箱。"}
    if len(password) < 6:
        return {"ok": False, "message": "密码至少6位。"}
    store = load_users()
    users = store.setdefault("users", {})
    if email in users:
        return {"ok": False, "message": "该邮箱已注册，请直接登录。"}
    salt = secrets.token_hex(12)
    users[email] = {
        "email": email,
        "nickname": nickname,
        "avatar": avatar,
        "salt": salt,
        "password": hash_password(password, salt),
        "plan": "体验版",
        "createdAt": datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "watchLimit": 1,
        "aiReviewLimit": 5,
    }
    if email in configured_admin_emails():
        users[email]["role"] = "admin"
    save_users(store)
    token = create_session(email)
    handler.send_response(200)
    handler.send_header("Content-Type", "application/json; charset=utf-8")
    set_session_cookie(handler, token)
    payload = json.dumps({"ok": True, "message": "注册成功。", "account": public_user(users[email])}, ensure_ascii=False).encode("utf-8")
    handler.send_header("Content-Length", str(len(payload)))
    handler.end_headers()
    handler.wfile.write(payload)
    return None


def login_payload(handler: Handler, data: dict) -> dict | None:
    email = str(data.get("email") or "").strip().lower()
    password = str(data.get("password") or "")
    throttle_key = login_throttle_key(handler, email)
    blocked = login_block_seconds(throttle_key)
    if blocked > 0:
        return {"ok": False, "message": f"登录尝试过多，请 {max(1, blocked // 60)} 分钟后再试。"}
    store = load_users()
    users = store.get("users", {})
    user = users.get(email)
    if not user or not verify_password(password, user):
        record_login_failure(throttle_key)
        return {"ok": False, "message": "邮箱或密码不正确。"}
    clear_login_failures(throttle_key)
    maybe_upgrade_password(password, user, store)
    token = create_session(email)
    handler.send_response(200)
    handler.send_header("Content-Type", "application/json; charset=utf-8")
    set_session_cookie(handler, token)
    payload = json.dumps({"ok": True, "message": "登录成功。", "account": public_user(user)}, ensure_ascii=False).encode("utf-8")
    handler.send_header("Content-Length", str(len(payload)))
    handler.end_headers()
    handler.wfile.write(payload)
    return None


def logout_payload(handler: Handler) -> None:
    cookie = handler.headers.get("Cookie", "")
    m = re.search(r"session=([a-f0-9]+)", cookie)
    if m:
        remove_session(m.group(1))
    handler.send_response(200)
    handler.send_header("Content-Type", "application/json; charset=utf-8")
    handler.send_header("Set-Cookie", "session=; Path=/; Max-Age=0; HttpOnly; SameSite=Lax")
    payload = json.dumps({"ok": True, "message": "已退出。"}, ensure_ascii=False).encode("utf-8")
    handler.send_header("Content-Length", str(len(payload)))
    handler.end_headers()
    handler.wfile.write(payload)
    return None


def account_payload(handler: Handler) -> dict:
    email = current_email(handler)
    if not email:
        return {"ok": False, "loggedIn": False, "message": "未登录。"}
    user = load_users().get("users", {}).get(email)
    if not user:
        return {"ok": False, "loggedIn": False, "message": "账号不存在。"}
    return {"ok": True, "loggedIn": True, "account": public_user(user)}


def configured_admin_emails() -> set[str]:
    return {item.strip().lower() for item in os.environ.get("DASHBOARD_ADMINS", "").split(",") if item.strip()}


def is_admin_email(email: str | None) -> bool:
    email = str(email or "").strip().lower()
    if not email:
        return False
    env_admins = configured_admin_emails()
    if email in env_admins:
        return True
    users = load_users().get("users", {})
    user = users.get(email) or {}
    return str(user.get("role") or "").lower() == "admin"


def account_watch_limit(email: str | None) -> int:
    email = str(email or "").strip().lower()
    user = load_users().get("users", {}).get(email) if email else None
    if not user:
        return 20
    if str(user.get("plan") or "") == "体验版" and int(user.get("watchLimit") or 1) <= 1:
        return 20
    return clamp_int(user.get("watchLimit"), 1, 1, 500)


def admin_users_payload() -> dict:
    store = load_users()
    load_sessions()
    active = {email for token, email in SESSIONS.items() if SESSION_EXPIRES.get(token, 0) > time_mod.time()}
    rows = []
    for email, user in sorted(store.get("users", {}).items()):
        row = public_user(user)
        row["loggedIn"] = email in active
        rows.append(row)
    return {"ok": True, "users": rows, "count": len(rows)}

def repair_mojibake_text(value: object) -> str:
    text = str(value or "").strip()
    if not text:
        return ""
    if "?" in text:
        return text
    try:
        fixed = text.encode("gbk").decode("utf-8")
        if fixed and fixed != text:
            return fixed
    except Exception:
        pass
    return text

def public_user(user: dict) -> dict:
    email = str(user.get("email") or "").strip().lower()
    nickname = repair_mojibake_text(user.get("nickname")) or email.split("@")[0]
    if "?" in nickname:
        nickname = email.split("@")[0] or "用户"
    plan = repair_mojibake_text(user.get("plan")) or "体验版"
    if "浣撻獙" in plan or "?" in plan:
        plan = "体验版"
    return {
        "email": user.get("email"),
        "nickname": nickname,
        "avatar": clamp_int(user.get("avatar"), 1, 1, 10),
        "plan": plan,
        "planExpireAt": user.get("planExpireAt", ""),
        "createdAt": user.get("createdAt"),
        "watchLimit": account_watch_limit(email),
        "aiReviewLimit": user.get("aiReviewLimit", 5),
        "role": user.get("role", ""),
        "isAdmin": is_admin_email(email),
    }


def save_account_avatar(email: str | None, data: dict) -> dict:
    normalized = str(email or "").strip().lower()
    if not normalized:
        return {"ok": False, "message": "请先登录。"}
    store = load_users()
    users = store.get("users") if isinstance(store.get("users"), dict) else {}
    user = users.get(normalized)
    if not isinstance(user, dict):
        return {"ok": False, "message": "账号不存在。"}
    avatar = clamp_int(data.get("avatar"), 1, 1, 10)
    user["avatar"] = avatar
    save_users(store)
    with AUTO_T_STATE_LOCK:
        state = _load_auto_t_state(normalized)
        if state.get("version") == 2:
            state["ownerAvatar"] = avatar
            try:
                _save_auto_t_state(normalized, state)
            except Exception:
                pass
    return {"ok": True, "message": "头像已更新。", "account": public_user(user)}


def dashboard_watchlist(email: str | None = None):
    try:
        from monitor_config import DEFAULT_WATCHLIST, parse_watchlist_text
    except Exception:
        return []
    data = read_dashboard_settings_file(email)
    text = str(data.get("watchlistText") or "").strip()
    stocks = parse_watchlist_text(text) if text else []
    return stocks or list(DEFAULT_WATCHLIST)


def dashboard_watchlist_text(stocks=None, email: str | None = None) -> str:
    try:
        from monitor_config import watchlist_text
        return watchlist_text(stocks or dashboard_watchlist(email))
    except Exception:
        return ""


def quote_age_seconds(quote) -> float | None:
    raw = str(getattr(quote, "time_raw", "") or "")
    if not raw or len(raw) < 14:
        return None
    try:
        dt = datetime.strptime(raw[:14], "%Y%m%d%H%M%S")
        return max(0.0, (datetime.now() - dt).total_seconds())
    except Exception:
        return None


def _market_value(item, key: str, default=0):
    if isinstance(item, dict):
        return item.get(key, default)
    return getattr(item, key, default)


def _market_number(item, key: str, default: float = 0.0) -> float:
    try:
        return float(_market_value(item, key, default) or default)
    except (TypeError, ValueError):
        return float(default)


def _hhmm_minutes(value: str) -> int:
    raw = str(value or "").strip()
    match = re.search(r"(\d{2}):(\d{2})", raw)
    if not match and len(raw) >= 12 and raw[:12].isdigit():
        match = re.search(r"(\d{2})(\d{2})$", raw[:12])
    if not match:
        return -1
    hour, minute = int(match.group(1)), int(match.group(2))
    return hour * 60 + minute if 0 <= hour <= 23 and 0 <= minute <= 59 else -1


def _ema_series(values: list[float], period: int) -> list[float]:
    if not values:
        return []
    alpha = 2.0 / (period + 1.0)
    out = [float(values[0])]
    for value in values[1:]:
        out.append(alpha * float(value) + (1.0 - alpha) * out[-1])
    return out


def _rsi_series(prices: list[float], period: int = 6) -> list[float]:
    values = [float(price) for price in prices if price and price > 0]
    if len(values) < 3:
        return [50.0] * len(values)
    alpha = 1.0 / max(1, period)
    avg_gain = avg_loss = 0.0
    out = [50.0]
    for index in range(1, len(values)):
        change = values[index] - values[index - 1]
        gain, loss = max(change, 0.0), max(-change, 0.0)
        if index == 1:
            avg_gain, avg_loss = gain, loss
        else:
            avg_gain = alpha * gain + (1.0 - alpha) * avg_gain
            avg_loss = alpha * loss + (1.0 - alpha) * avg_loss
        if avg_loss <= 1e-9:
            out.append(100.0 if avg_gain > 0 else 50.0)
        else:
            rs = avg_gain / avg_loss
            out.append(100.0 - 100.0 / (1.0 + rs))
    return out


def _kdj_j_series(prices: list[float], period: int = 9) -> list[float]:
    if not prices:
        return []
    k = d = 50.0
    out = []
    for index, close in enumerate(prices):
        window = prices[max(0, index - period + 1) : index + 1]
        low, high = min(window), max(window)
        rsv = (close - low) / (high - low) * 100.0 if high > low else 50.0
        k = (2.0 * k + rsv) / 3.0
        d = (2.0 * d + k) / 3.0
        out.append(3.0 * k - 2.0 * d)
    return out


def _atr_proxy(prices: list[float], period: int = 14) -> float:
    if len(prices) < 2:
        return 0.0
    changes = [abs(prices[index] - prices[index - 1]) for index in range(1, len(prices))]
    return _ema_series(changes, period)[-1]


def _minute_volume_values(rows: list) -> list[float]:
    raw = []
    for row in rows:
        value = _market_number(row, "volume_lot") or _market_number(row, "volume")
        raw.append(max(0.0, value))
    if len(raw) > 2 and all(raw[index] >= raw[index - 1] for index in range(1, len(raw))):
        return [raw[0]] + [max(0.0, raw[index] - raw[index - 1]) for index in range(1, len(raw))]
    return raw


def _confirmed_pivot(prices: list[float], left: int = 2, right: int = 2) -> tuple[str, float]:
    if len(prices) < left + right + 1:
        return "", 0.0
    center = len(prices) - right - 1
    value = prices[center]
    before = prices[center - left : center]
    after = prices[center + 1 : center + right + 1]
    nearby = prices[max(0, center - 7) : center + right + 1]
    if all(value > other for other in before + after) and value >= max(nearby):
        return "top", value
    if all(value < other for other in before + after) and value <= min(nearby):
        return "bottom", value
    return "", 0.0


def intraday_reminder_payload(quote, minutes, avg: float, time_text: str = "", stock_code: str = "") -> dict:
    """Deterministic opening-path and intraday overbought/oversold reminder."""
    rows = list(minutes or [])
    prices = [_market_number(row, "price") for row in rows]
    prices = [price for price in prices if price > 0]
    current = _market_number(quote, "price", prices[-1] if prices else 0.0)
    previous = _market_number(quote, "pre_close") or current
    open_price = prices[0] if prices else current
    minute_text = time_text or str(_market_value(quote, "time_raw", ""))
    current_minute = _hhmm_minutes(minute_text)
    opening_active = 9 * 60 + 25 <= current_minute < 10 * 60

    early_prices = []
    for row in rows:
        row_minute = _hhmm_minutes(str(_market_value(row, "time", "")))
        price = _market_number(row, "price")
        if price > 0 and (row_minute < 0 or row_minute <= 10 * 60):
            early_prices.append(price)
    path_price = current if opening_active else (early_prices[-1] if early_prices else current)
    gap_pct = (open_price - previous) / previous * 100.0 if previous > 0 else 0.0
    open_move = (path_price - open_price) / open_price * 100.0 if open_price > 0 else 0.0
    avg_dev = (current - avg) / avg * 100.0 if avg and current > 0 else 0.0

    label, tone = "平开震荡", "wait"
    if current_minute >= 0 and current_minute < 9 * 60 + 30 and not prices:
        if gap_pct >= 0.30:
            label = "高开观察"
        elif gap_pct <= -0.30:
            label = "低开观察"
        else:
            label = "竞价平开"
    elif gap_pct >= 0.30:
        if open_move <= -0.35 or (avg and path_price < avg * 0.998):
            label, tone = "高开低走", "sell"
        elif open_move >= 0.25 and (not avg or path_price >= avg):
            label, tone = "高开高走", "buy"
        else:
            label = "高开震荡"
    elif gap_pct <= -0.30:
        if open_move >= 0.35 or (avg and path_price > avg * 1.002):
            label, tone = "低开高走", "buy"
        elif open_move <= -0.25:
            label, tone = "低开低走", "sell"
        else:
            label = "低开震荡"
    elif open_move >= 0.35:
        label, tone = "平开上攻", "buy"
    elif open_move <= -0.35:
        label, tone = "平开走弱", "sell"

    opening_reason_map = {
        "高开低走": "高开后跌回开盘价，先防冲高回落。",
        "低开高走": "低开后持续回收，关注黄线承接。",
        "高开高走": "高开延续偏强，不追高，等回踩。",
        "低开低走": "低开后继续转弱，先不急着低吸。",
        "平开上攻": "平开后向上，等待回踩确认。",
        "平开走弱": "平开后走弱，先观察止跌。",
        "高开观察": "集合竞价高开，等开盘方向确认。",
        "低开观察": "集合竞价低开，等开盘承接确认。",
        "竞价平开": "集合竞价平稳，等开盘方向确认。",
    }
    opening_reason = opening_reason_map.get(label, "方向未定，先看黄线与开盘价。")
    opening_actionable = opening_active and label in {"高开低走", "低开高走", "高开高走", "低开低走", "平开上攻", "平开走弱"}

    day_prices = prices + ([current] if current > 0 and (not prices or current != prices[-1]) else [])
    recent_30 = day_prices[-30:]
    recent_20 = day_prices[-20:]
    day_low = min(day_prices) if day_prices else current
    day_high = max(day_prices) if day_prices else current
    range_low = min(recent_30) if recent_30 else day_low
    range_high = max(recent_30) if recent_30 else day_high
    range_span = max(range_high - range_low, 0.0)
    range_position = (current - range_low) / range_span * 100.0 if range_span > 1e-9 else 50.0
    rsi_values = _rsi_series(day_prices, 6)
    rsi = rsi_values[-1] if rsi_values else 50.0
    kdj_values = _kdj_j_series(day_prices)
    kdj_j = kdj_values[-1] if kdj_values else 50.0
    ema5_values = _ema_series(day_prices, 5)
    ema5 = ema5_values[-1] if ema5_values else current
    atr = _atr_proxy(day_prices, 14)
    volumes = _minute_volume_values(rows)
    volume_base = volumes[-21:-1]
    volume_avg = sum(volume_base) / len(volume_base) if volume_base else 0.0
    volume_ratio = volumes[-1] / volume_avg if volumes and volume_avg > 0 else 0.0
    previous_price = day_prices[-2] if len(day_prices) >= 2 else current
    recent_high = max(recent_20) if recent_20 else current
    recent_low = min(recent_20) if recent_20 else current
    new_high = current >= recent_high - 1e-9
    new_low = current <= recent_low + 1e-9
    top_divergence = len(day_prices) >= 8 and new_high and rsi <= max(rsi_values[-7:-1]) - 5.0
    bottom_divergence = len(day_prices) >= 8 and new_low and rsi >= min(rsi_values[-7:-1]) + 5.0
    price_turn_down = len(day_prices) >= 3 and day_prices[-1] < day_prices[-2] <= day_prices[-3]
    price_turn_up = len(day_prices) >= 3 and day_prices[-1] > day_prices[-2] >= day_prices[-3]
    volume_stall_top = volume_ratio >= 1.2 and current < recent_high
    volume_stall_bottom = volume_ratio >= 1.2 and current > recent_low

    top_zone_flags = [range_position >= 85.0, atr > 0 and current >= avg + 1.2 * atr, rsi >= 80.0, kdj_j >= 100.0, new_high]
    bottom_zone_flags = [range_position <= 15.0, atr > 0 and current <= avg - 1.2 * atr, rsi <= 20.0, kdj_j <= 0.0, new_low]
    top_zone = sum(top_zone_flags) >= 2
    bottom_zone = sum(bottom_zone_flags) >= 2
    top_reversal_flags = [current < previous_price, current < ema5, price_turn_down, volume_stall_top, top_divergence]
    bottom_reversal_flags = [current > previous_price, current > ema5, price_turn_up, volume_stall_bottom, bottom_divergence]
    top_reversal = sum(top_reversal_flags) >= 2
    bottom_reversal = sum(bottom_reversal_flags) >= 2

    top_score = (
        15 * int(range_position >= 85.0)
        + 15 * int(atr > 0 and current >= avg + 1.2 * atr)
        + 15 * int(rsi >= 80.0 or kdj_j >= 100.0)
        + 20 * int(top_divergence)
        + 15 * int(price_turn_down or volume_stall_top)
        + 20 * int(current < ema5 and current < previous_price)
    )
    bottom_score = (
        15 * int(range_position <= 15.0)
        + 15 * int(atr > 0 and current <= avg - 1.2 * atr)
        + 15 * int(rsi <= 20.0 or kdj_j <= 0.0)
        + 20 * int(bottom_divergence)
        + 15 * int(price_turn_up or volume_stall_bottom)
        + 20 * int(current > ema5 and current > previous_price)
    )

    five_minute = day_prices[4::5]
    if day_prices and (not five_minute or five_minute[-1] != day_prices[-1]):
        five_minute.append(day_prices[-1])
    five_ema = _ema_series(five_minute, 20)
    trend_up = len(five_minute) >= 4 and current > avg and five_ema[-1] > five_ema[-3]
    trend_down = len(five_minute) >= 4 and current < avg and five_ema[-1] < five_ema[-3]
    top_threshold = 85 if trend_up else 80
    bottom_threshold = 85 if trend_down else 80
    if trend_up:
        top_score = max(0, top_score - 10)
        bottom_score = min(100, bottom_score + 5)
    elif trend_down:
        bottom_score = max(0, bottom_score - 10)
        top_score = min(100, top_score + 5)

    pivot_side, pivot_price = _confirmed_pivot(day_prices, 2, 2)
    top_confirmed = top_zone and top_reversal and top_score >= top_threshold
    bottom_confirmed = bottom_zone and bottom_reversal and bottom_score >= bottom_threshold
    if pivot_side == "top" and range_position >= 55.0:
        top_confirmed, top_score = True, max(top_score, 82)
    elif pivot_side == "bottom" and range_position <= 45.0:
        bottom_confirmed, bottom_score = True, max(bottom_score, 82)

    reminder_label, reminder_tone, reminder_actionable = "盘中平稳", "wait", False
    reminder_score, reference_price = max(top_score, bottom_score), 0.0
    reminder_reason = "未进入高低位观察区。"
    side = ""
    if top_confirmed and top_score >= bottom_score:
        reminder_label, reminder_tone, side = "局部顶部确认", "sell", "top"
        reference_price = pivot_price or recent_high
        reminder_reason = f"参考高点 {reference_price:.2f}，跌破EMA5后确认。"
    elif bottom_confirmed and bottom_score > top_score:
        reminder_label, reminder_tone, side = "局部低点确认", "buy", "bottom"
        reference_price = pivot_price or recent_low
        reminder_reason = f"参考低点 {reference_price:.2f}，站上EMA5后确认。"
    elif top_score >= 65 and top_score >= bottom_score:
        reminder_label, reminder_tone, side = "疑似局部顶部", "sell", "top"
        reminder_reason = "高位信号增强，等待反转确认。"
    elif bottom_score >= 65 and bottom_score > top_score:
        reminder_label, reminder_tone, side = "疑似局部低点", "buy", "bottom"
        reminder_reason = "低位信号增强，等待反转确认。"
    elif (top_score >= 50 or top_zone) and top_score >= bottom_score:
        reminder_label, reminder_tone, side = "高位超买", "sell", "top"
        reminder_reason = "接近30分钟上沿，等待跌破EMA5确认。"
    elif bottom_score >= 50 or bottom_zone:
        reminder_label, reminder_tone, side = "低位超卖", "buy", "bottom"
        reminder_reason = "接近30分钟下沿，等待站上EMA5确认。"

    if reminder_label in {"局部顶部确认", "局部低点确认"}:
        state_key = stock_code or str(_market_value(quote, "name", "stock"))
        state = INTRADAY_REMINDER_STATE.setdefault(state_key, {})
        last_side = str(state.get("side") or "")
        last_minute = int(state.get("minute") or -9999)
        cooled_down = side != last_side or current_minute < 0 or current_minute - last_minute >= 5
        reminder_actionable = cooled_down
        if cooled_down:
            state.update({"side": side, "minute": current_minute, "score": reminder_score})
        else:
            reminder_reason += " 同向提醒冷却中。"

    opening_guard = "重新站稳黄线再确认。" if tone == "sell" else "回踩不破黄线再确认。" if tone == "buy" else "方向不清先等待。"
    reminder_guard = "观察区不等于买卖点，确认后再执行。"
    return {
        "opening": {
            "active": opening_active,
            "actionable": opening_actionable,
            "label": label,
            "tone": tone,
            "reason": opening_reason,
            "guard": opening_guard,
            "window": "09:25-10:00 开盘判断",
            "gapPct": round(gap_pct, 2),
            "openMovePct": round(open_move, 2),
        },
        "reminder": {
            "active": current_minute >= 9 * 60 + 30,
            "actionable": reminder_actionable,
            "label": reminder_label,
            "tone": reminder_tone,
            "reason": reminder_reason,
            "guard": reminder_guard,
            "rsi": round(rsi, 1),
            "kdjJ": round(kdj_j, 1),
            "atr": round(atr, 4),
            "ema5": round(ema5, 3),
            "volumeRatio": round(volume_ratio, 2),
            "rangePosition": round(range_position, 1),
            "avgDev": round(avg_dev, 2),
            "score": int(reminder_score),
            "topScore": int(top_score),
            "bottomScore": int(bottom_score),
            "referencePrice": round(reference_price, 3),
            "pivotDelay": 2 if pivot_side else 0,
            "trend5m": "向上" if trend_up else "向下" if trend_down else "震荡",
        },
    }


def normalized_market_points(minutes: list, quote: object = None) -> list[dict]:
    """Normalize mixed vendor volume semantics into cumulative + per-minute fields."""
    rows = list(minutes or [])
    raw_volumes = [max(0.0, _market_number(item, "volume_lot") or _market_number(item, "volume")) for item in rows]
    raw_amounts = [max(0.0, _market_number(item, "amount_yuan") or _market_number(item, "amount")) for item in rows]
    quote_volume = max(0.0, _market_number(quote, "volume_lot"))
    quote_amount = max(0.0, _market_number(quote, "amount_wan") * 10000.0)

    def is_cumulative(values: list[float], total: float) -> bool:
        positive = [value for value in values if value > 0]
        if len(positive) < 2:
            return False
        last, summed = positive[-1], sum(positive)
        if total > 0:
            return abs(last - total) <= abs(summed - total)
        non_decreasing = sum(values[index] >= values[index - 1] for index in range(1, len(values))) / max(1, len(values) - 1)
        return non_decreasing >= 0.96 and last >= summed * 0.35

    volume_cumulative = is_cumulative(raw_volumes, quote_volume)
    amount_cumulative = is_cumulative(raw_amounts, quote_amount)
    output: list[dict] = []
    running_volume = running_amount = 0.0
    previous_volume = previous_amount = 0.0
    for item, raw_volume, raw_amount in zip(rows, raw_volumes, raw_amounts):
        minute_volume = max(0.0, raw_volume - previous_volume) if volume_cumulative and raw_volume >= previous_volume else raw_volume
        minute_amount = max(0.0, raw_amount - previous_amount) if amount_cumulative and raw_amount >= previous_amount else raw_amount
        running_volume = raw_volume if volume_cumulative and raw_volume >= previous_volume else running_volume + minute_volume
        running_amount = raw_amount if amount_cumulative and raw_amount >= previous_amount else running_amount + minute_amount
        previous_volume, previous_amount = raw_volume, raw_amount
        output.append({
            "time": str(_market_value(item, "time", "")),
            "price": _market_number(item, "price"),
            "volume": round(running_volume, 4),
            "volumeDelta": round(minute_volume, 4),
            "amount": round(running_amount, 2),
            "amountDelta": round(minute_amount, 2),
            "volumeMode": "cumulative" if volume_cumulative else "minute",
        })
    return output



def demo_realtime_payload(email: str | None = None, error: str = "") -> dict:
    """Self-contained demo data so the cockpit can preview even when行情模块缺失."""
    def minute_points(base: float, last: float, seed: int = 7):
        random.seed(seed)
        times = []
        # 09:30-11:30 每5分钟，13:00-15:00 每5分钟，加最后15:51展示
        h, m = 9, 30
        while h < 11 or (h == 11 and m <= 30):
            times.append(f"{h:02d}:{m:02d}")
            m += 5
            if m >= 60:
                h += 1
                m -= 60
        h, m = 13, 0
        while h < 15 or (h == 15 and m <= 0):
            times.append(f"{h:02d}:{m:02d}")
            m += 5
            if m >= 60:
                h += 1
                m -= 60
        times.append("15:51")
        pts = []
        n = len(times)
        value = base
        total_vol = 0
        total_amt = 0.0
        for i, t in enumerate(times):
            x = i / max(1, n - 1)
            # 低开后震荡，午后小反抽再回落，贴近截图模板
            curve = -0.20 - 0.28 * math.sin(min(x * math.pi * 1.35, math.pi)) + 0.09 * math.sin(x * math.pi * 5.1)
            drift = (last - base) * x
            noise = random.uniform(-0.018, 0.018)
            value = max(0.01, base + drift + curve + noise)
            if i == n - 1:
                value = last
            inc_vol = int((4200 + random.random() * 6500) * (1.8 if i in (0, 1, n - 2, n - 1) else 1.0))
            total_vol += inc_vol
            total_amt += inc_vol * value * 100
            pts.append({"time": t, "price": round(value, 2), "volume": total_vol, "amount": round(total_amt, 2)})
        return pts

    stocks = [
        ("隆基绿能", "601012", 11.74, -3.85, 12.21, 12.19, 11.73, 1239300, 1471000000, 11.86, "继续观察"),
        ("宁德时代", "300750", 250.82, -1.12, 253.66, 254.70, 248.10, 386200, 973000000, 251.60, "继续观察"),
        ("比亚迪", "002594", 108.40, 0.76, 107.58, 109.22, 106.90, 224600, 244000000, 107.90, "继续观察"),
        ("中国平安", "601318", 42.10, -0.48, 42.30, 42.48, 41.82, 592100, 249300000, 42.18, "继续观察"),
    ]
    rows = []
    for idx, (name, code, price, chg, prev, high, low, vol, amount, avg, signal) in enumerate(stocks):
        pts = minute_points(prev, price, seed=idx + 5)
        snapshot = intraday_reminder_payload(
            {"name": name, "price": price, "pre_close": prev, "time_raw": "15:51"},
            pts,
            avg,
            "15:51",
            code,
        )
        rows.append({
            "name": name,
            "code": code,
            "time": "15:51",
            "price": price,
            "change": chg,
            "changeAmount": round(price - prev, 2),
            "prevClose": prev,
            "open": pts[0]["price"],
            "high": high,
            "low": low,
            "volume": vol,
            "amount": amount,
            "avg": avg,
            "dev": round((price - avg) / max(avg, 0.01) * 100, 2),
            "signal": signal,
            "reason": "早盘还没有出现直接买卖点，先盯住前10分钟黄线与回踩承接。",
            "strictSignal": False,
            "marketStatus": "休市中",
            "quoteAgeSeconds": 0,
            "quoteStale": False,
            "prices": pts,
            "buyTime": "13:30" if idx == 0 else "",
            "sellTime": "13:58" if idx == 0 else "",
            "buyPrice": round(price + 0.03, 2) if idx == 0 else 0,
            "sellPrice": round(price + 0.31, 2) if idx == 0 else 0,
            "smartMoney": {},
            "rapidNews": {},
            "opening": snapshot["opening"],
            "intradayReminder": snapshot["reminder"],
            "agents": ["买兔：等待黄线承接", "卖兔：不追高，先看回落", "风控兔：未共振就观察"],
        })
    smart_profile = str(load_profit_strategy_settings(email).get("smartTProfile") or "balanced")
    for row in rows:
        row["rawStrictSignal"] = bool(row.get("strictSignal"))
        auction_gate = evaluate_auction_gate(
            pre_close=row.get("prevClose"),
            open_price=row.get("open"),
            current_price=row.get("price"),
            average=row.get("avg"),
            points=row.get("prices") or [],
            time_text=row.get("time"),
        )
        row["auctionRadar"] = auction_gate
        if isinstance(row.get("opening"), dict):
            row["opening"]["auctionGate"] = auction_gate
        row["smartT"] = evaluate_smart_t(
            profile=smart_profile,
            time_text=row.get("time"),
            price=row.get("price"),
            average=row.get("avg"),
            high=row.get("high"),
            low=row.get("low"),
            points=row.get("prices") or [],
            signal_action=row.get("signal"),
            signal_score=(row.get("intradayReminder") or {}).get("score", 0),
            strict_signal=bool(row.get("strictSignal")),
            quote_stale=bool(row.get("quoteStale")),
            market_status=row.get("marketStatus"),
            auction_direction=auction_gate.get("preferredDirection"),
            auction_state=auction_gate.get("state"),
        )
    ranking = auto_t_update(rows, email)
    return {"ok": True, "demo": True, "message": "使用内置演示行情预览界面。" + (f" 行情模块：{error}" if error else ""), "stocks": rows, "paperRanking": ranking}

def realtime_payload(email: str | None = None) -> dict:
    try:
        import stock_t_signal as signal_mod
        from stock_t_signal import analyze, analyze_observation, fetch_minutes, fetch_quote, _format_time, _vwap
    except Exception as exc:
        return demo_realtime_payload(email, str(exc))

    rows = []
    signal_mod.ADAPTIVE_STRATEGY_PATH = account_strategy_path(email)
    market_context = cached_market_context()
    smart_settings = load_profit_strategy_settings(email)
    smart_profile = str(smart_settings.get("smartTProfile") or "balanced")
    for stock in dashboard_watchlist(email)[: account_watch_limit(email)]:
        try:
            quote = fetch_quote(stock.symbol)
            minutes = fetch_minutes(stock.symbol)
            avg = _vwap(quote, minutes) if quote else None
            quote_time = _format_time(quote.time_raw, minutes) if quote else "--:--"
            auction_price = auction_snapshot_price(email, stock.code, quote_time, quote) if quote else 0.0
            snapshot = intraday_reminder_payload(quote, minutes, avg or 0, quote_time, stock.code)
            opening_view = snapshot["opening"]
            reminder_view = snapshot["reminder"]
            quote_minute = _hhmm_minutes(quote_time)
            strict_signals = analyze(stock)
            signals = strict_signals or analyze_observation(stock)
            dev = (quote.price - avg) / avg * 100.0 if quote and avg else 0.0
            signal = signals[0] if signals else None
            strict_signal = bool(strict_signals)
            age_seconds = quote_age_seconds(quote) if quote else None
            quote_stale = bool(market_is_open() and age_seconds is not None and age_seconds > 90)
            if quote_stale:
                signal = None
            signal_action = signal.action if signal else ""
            is_buy_signal = any(word in signal_action for word in ("低吸", "买入"))
            is_sell_signal = any(word in signal_action for word in ("高抛", "卖出"))
            is_open = market_is_open()
            rapid_news = rapid_news_payload(stock.name, stock.code, minutes, quote)
            agents = monitor_agents_payload(stock.name, quote, minutes, avg, dev, signal, is_open, market_context, gemini_cached_advice(stock.code))
            agents.insert(0, f"开盘路径：{opening_view['label']}｜{opening_view['reason']}")
            agents.insert(1, f"盘中提醒：{reminder_view['label']} {reminder_view['score']}分｜{reminder_view['reason']}")
            if rapid_news.get("active"):
                agents.insert(2, rapid_news_agent(rapid_news))
            if quote_stale:
                display_signal, display_reason = "行情延迟", f"报价时间超过{int(age_seconds or 0)}秒未更新，暂停买卖点提醒，等待下一笔有效行情。"
            else:
                display_signal, display_reason = news_adjusted_signal(signal.action if signal else ("观察" if is_open else "休市中"), signal.reason if signal else ("暂无高质量买卖点" if is_open else "当前休市，仅显示最近分时数据"), rapid_news)
                if opening_view["active"]:
                    display_signal, display_reason = opening_view["label"], opening_view["reason"]
                elif reminder_view["label"] != "盘中平稳" and (reminder_view["actionable"] or not strict_signal):
                    display_signal, display_reason = reminder_view["label"], reminder_view["reason"]
            price_points = normalized_market_points(minutes, quote)
            signal_price = float(getattr(signal, "price", 0) or 0) if signal else 0.0
            if quote:
                previous_point = price_points[-1] if price_points else {}
                quote_total_volume = max(0.0, _market_number(quote, "volume_lot"))
                quote_total_amount = max(0.0, _market_number(quote, "amount_wan") * 10000.0)
                latest_point = {
                    "time": quote_time,
                    "price": quote.price,
                    "volume": quote_total_volume,
                    "volumeDelta": max(0.0, quote_total_volume - _auto_t_number(previous_point.get("volume"))),
                    "amount": quote_total_amount,
                    "amountDelta": max(0.0, quote_total_amount - _auto_t_number(previous_point.get("amount"))),
                    "volumeMode": "cumulative",
                    "realtime": True,
                }
                if price_points and price_points[-1].get("time") == quote_time:
                    price_points[-1].update(latest_point)
                elif quote_time and quote_time != "--:--":
                    price_points.append(latest_point)
            auction_gate = evaluate_auction_gate(
                pre_close=quote.pre_close if quote else 0,
                open_price=minutes[0].price if minutes else (quote.price if quote else 0),
                current_price=quote.price if quote else 0,
                average=avg or 0,
                points=price_points,
                time_text=quote_time,
                auction_price=auction_price,
            )
            opening_view["auctionGate"] = auction_gate
            opening_view["stockSpecific"] = True
            opening_view["planLabel"] = str(auction_gate.get("label") or "本股独立观察")
            opening_view["planReason"] = str(auction_gate.get("reason") or "")
            agents.insert(0, f"本股竞价预案：{auction_gate.get('label')}｜{auction_gate.get('reason')}｜数据：{auction_gate.get('source')}")
            if auction_gate.get("state") == "CONFIRMED":
                opening_view.update(
                    actionable=True,
                    label=str(auction_gate.get("label") or opening_view.get("label")),
                    tone="buy" if auction_gate.get("preferredDirection") == "BUY_FIRST" else "sell",
                    reason=str(auction_gate.get("reason") or opening_view.get("reason")),
                )
            reminder_is_confirmed = bool(reminder_view.get("actionable") and reminder_view.get("tone") in {"buy", "sell"})
            policy_action = signal_action
            if not policy_action and reminder_is_confirmed:
                policy_action = "买入确认" if reminder_view.get("tone") == "buy" else "卖出确认"
            policy_score = max(
                int(getattr(signal, "score", 0) or 0) if signal else 0,
                round(float(reminder_view.get("score") or 0) / 10) if reminder_is_confirmed else 0,
            )
            smart_t = evaluate_smart_t(
                profile=smart_profile,
                time_text=quote_time,
                price=quote.price if quote else 0,
                average=avg or 0,
                high=quote.high if quote else 0,
                low=quote.low if quote else 0,
                points=price_points,
                signal_action=policy_action,
                signal_score=policy_score,
                strict_signal=bool(strict_signal or reminder_is_confirmed),
                quote_stale=quote_stale,
                market_status="交易中" if is_open else "休市中",
                auction_direction=auction_gate.get("preferredDirection"),
                auction_state=auction_gate.get("state"),
            )
            raw_display_signal, raw_display_reason = display_signal, display_reason
            if (strict_signal or reminder_is_confirmed) and not smart_t.get("confirmed"):
                display_signal = "智能做T·暂缓"
                display_reason = f"{smart_t.get('reason')} 原信号：{raw_display_signal}｜{raw_display_reason}"
            elif smart_t.get("confirmed"):
                display_reason = f"{smart_t.get('reason')} {raw_display_reason}"
            rows.append(
                {
                    "name": stock.name,
                    "code": stock.code,
                    "time": _format_time(quote.time_raw, minutes) if quote else "--:--",
                    "price": quote.price if quote else 0,
                    "change": quote.change_pct if quote else 0,
                    "changeAmount": (quote.price - quote.pre_close) if quote else 0,
                    "prevClose": quote.pre_close if quote else 0,
                    "open": minutes[0].price if minutes else (quote.price if quote else 0),
                    "high": quote.high if quote else 0,
                    "low": quote.low if quote else 0,
                    "volume": quote.volume_lot if quote else 0,
                    "amount": (quote.amount_wan * 10000.0) if quote else 0,
                    "avg": avg or 0,
                    "dev": dev,
                    "signal": display_signal,
                    "reason": display_reason,
                    "strictSignal": bool(smart_t.get("confirmed")),
                    "rawStrictSignal": strict_signal,
                    "rawSignal": raw_display_signal,
                    "signalScore": policy_score,
                    "smartT": smart_t,
                    "auctionRadar": auction_gate,
                    "marketStatus": "竞价中" if 9 * 60 + 25 <= quote_minute < 9 * 60 + 30 else ("交易中" if is_open else "休市中"),
                    "quoteAgeSeconds": age_seconds,
                    "quoteStale": quote_stale,
                    "prices": price_points,
                    "buyTime": signal.time if signal and is_buy_signal else "",
                    "sellTime": signal.time if signal and is_sell_signal else "",
                    "buyPrice": signal_price if signal and is_buy_signal else 0,
                    "sellPrice": signal_price if signal and is_sell_signal else 0,
                    "smartMoney": smart_money_payload(quote, minutes, avg, dev),
                    "rapidNews": rapid_news,
                    "opening": opening_view,
                    "intradayReminder": reminder_view,
                    "agents": agents,
                }
            )
        except Exception as exc:
            rows.append({"name": stock.name, "code": stock.code, "time": "--:--", "price": 0, "change": 0, "avg": 0, "dev": 0, "signal": "异常", "reason": str(exc)})
    ranking = auto_t_update(rows, email)
    return {"ok": True, "stocks": rows, "paperRanking": ranking}


def market_radar_payload(email: str | None = None) -> dict:
    """Build market radar from a broad A-share snapshot, with explicit fallback."""
    now = time_mod.time()
    broad_rows = list(MARKET_BREADTH_CACHE.get("rows") or []) if now - _auto_t_number(MARKET_BREADTH_CACHE.get("ts")) < 90 else []
    fetch_error = ""
    if not broad_rows:
        params = {
            "pn": "1", "pz": "6000", "po": "1", "np": "1", "fltt": "2", "invt": "2", "fid": "f3",
            "fs": "m:0+t:6,m:0+t:80,m:1+t:2,m:1+t:23",
            "fields": "f2,f3,f5,f6,f12,f14",
        }
        url = "https://push2.eastmoney.com/api/qt/clist/get?" + urllib.parse.urlencode(params)
        try:
            request = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0", "Referer": "https://quote.eastmoney.com/"})
            data = json.loads(urllib.request.urlopen(request, timeout=8).read().decode("utf-8", "replace"))
            diff = ((data.get("data") or {}).get("diff") or []) if isinstance(data, dict) else []
            broad_rows = [
                {
                    "code": str(item.get("f12") or ""),
                    "name": str(item.get("f14") or item.get("f12") or ""),
                    "price": _auto_t_number(item.get("f2")),
                    "change": _auto_t_number(item.get("f3")),
                    "volume": _auto_t_number(item.get("f5")),
                    "amount": _auto_t_number(item.get("f6")),
                }
                for item in diff if isinstance(item, dict) and _auto_t_number(item.get("f2")) > 0
            ]
            if len(broad_rows) < 300:
                raise ValueError(f"全市场样本仅{len(broad_rows)}只")
            MARKET_BREADTH_CACHE.update(ts=now, rows=broad_rows, error="")
        except Exception as exc:
            fetch_error = str(exc)
            MARKET_BREADTH_CACHE.update(ts=now, rows=[], error=fetch_error)
    if not broad_rows:
        # Sina's market-center endpoint caps one response at 100 rows.  Fetch
        # all pages concurrently so the radar still covers the entire A-share
        # universe when the primary breadth endpoint rejects the request.
        sina_base = "https://vip.stock.finance.sina.com.cn/quotes_service/api/json_v2.php/Market_Center.getHQNodeData?"

        def fetch_sina_page(page: int) -> list[dict]:
            query = urllib.parse.urlencode({
                "page": str(page), "num": "100", "sort": "symbol", "asc": "1",
                "node": "hs_a", "symbol": "", "_s_r_a": "init",
            })
            request = urllib.request.Request(
                sina_base + query,
                headers={"User-Agent": "Mozilla/5.0", "Referer": "https://finance.sina.com.cn/"},
            )
            raw = urllib.request.urlopen(request, timeout=12).read().decode("utf-8", "replace")
            data = json.loads(raw)
            return data if isinstance(data, list) else []

        try:
            pages: list[list[dict]] = []
            with concurrent.futures.ThreadPoolExecutor(max_workers=10) as executor:
                for page_rows in executor.map(fetch_sina_page, range(1, 61)):
                    pages.append(page_rows)
            broad_rows = [
                {
                    "code": str(item.get("code") or ""),
                    "name": str(item.get("name") or item.get("code") or ""),
                    "price": _auto_t_number(item.get("trade")),
                    "change": _auto_t_number(item.get("changepercent")),
                    "volume": _auto_t_number(item.get("volume")) / 100.0,
                    "amount": _auto_t_number(item.get("amount")),
                }
                for page_rows in pages for item in page_rows
                if isinstance(item, dict) and _auto_t_number(item.get("trade")) > 0
            ]
            unique_rows = {row["code"]: row for row in broad_rows if row["code"]}
            broad_rows = list(unique_rows.values())
            if len(broad_rows) < 1000:
                raise ValueError(f"备用全市场样本仅{len(broad_rows)}只")
            MARKET_BREADTH_CACHE.update(ts=now, rows=broad_rows, error="")
            fetch_error = ""
        except Exception as exc:
            fetch_error = "; ".join(part for part in (fetch_error, f"备用源：{exc}") if part)
            MARKET_BREADTH_CACHE.update(ts=now, rows=[], error=fetch_error)
    if broad_rows:
        payload = calculate_market_radar(broad_rows)
        payload.update({
            "demo": False,
            "dataSource": "全A股市场快照",
            "coverage": "full",
            "coverageMessage": f"已覆盖 {len(broad_rows)} 只有有效价格的沪深北A股；停牌或无有效报价证券不参与打分。",
        })
    else:
        realtime = realtime_payload(email)
        fallback_rows = realtime.get("stocks") or []
        payload = calculate_market_radar(fallback_rows)
        payload.update({
            "demo": bool(realtime.get("demo")),
            "dataSource": "自选股降级样本",
            "coverage": "degraded",
            "coverageMessage": f"全市场接口暂不可用，仅使用 {len(fallback_rows)} 只自选股，结论可信度较低。",
            "dataError": fetch_error or str(MARKET_BREADTH_CACHE.get("error") or ""),
        })
    payload["updatedAt"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    return update_radar_history(payload, user_data_path(email, "market_radar_history.json"))


PREMARKET_FUTURES = [
    ("黄金", "GC=F", "$/oz", 1.8),
    ("白银", "SI=F", "$/oz", 0.8),
    ("铜", "HG=F", "$/lb", 2.1),
    ("WTI原油", "CL=F", "$/bbl", 0.5),
    ("布油", "BZ=F", "$/bbl", 0.4),
    ("美元指数", "DX-Y.NYB", "", -1.6),
    ("离岸人民币", "CNH=X", "", -0.6),
]


def premarket_payload(code: str = "", email: str | None = None) -> dict:
    rows = []
    market_context = cached_market_context()
    with concurrent.futures.ThreadPoolExecutor(max_workers=7) as pool:
        futures = [pool.submit(fetch_yahoo_market, name, symbol, unit, weight) for name, symbol, unit, weight in PREMARKET_FUTURES]
        for future in concurrent.futures.as_completed(futures, timeout=12):
            item = future.result()
            if item:
                rows.append(item)
    order = {name: i for i, (name, *_rest) in enumerate(PREMARKET_FUTURES)}
    rows.sort(key=lambda row: order.get(row["name"], 99))
    target = premarket_target_stock(code, email)
    bias = premarket_stock_bias(rows, target)
    data = {"ok": True, "updatedAt": datetime.now().strftime("%m-%d %H:%M"), "rows": rows, "target": bias, "zijin": bias}
    MARKET_CONTEXT_CACHE["ts"] = datetime.now().timestamp()
    MARKET_CONTEXT_CACHE["data"] = data
    return data


def premarket_target_stock(code: str = "", email: str | None = None) -> dict:
    if code:
        try:
            from monitor_config import parse_stock_token
            stock = parse_stock_token(code)
            if stock:
                return {"name": stock.name, "code": stock.code, "symbol": stock.symbol}
        except Exception:
            pass
    try:
        stock = (dashboard_watchlist(email)[: account_watch_limit(email)] or [None])[0]
        if stock:
            return {"name": stock.name, "code": stock.code, "symbol": stock.symbol}
    except Exception:
        pass
    return {"name": "紫金矿业", "code": "601899", "symbol": "sh601899"}


def cached_market_context() -> dict:
    cached = MARKET_CONTEXT_CACHE.get("data") or {}
    if isinstance(cached, dict):
        return cached
    return {}


def rapid_news_payload(name: str, code: str, minutes: list, quote) -> dict:
    prices = [float(getattr(m, "price", 0) or 0) for m in minutes if float(getattr(m, "price", 0) or 0) > 0]
    if len(prices) < 6:
        return {"active": False}
    price = float(getattr(quote, "price", 0) or prices[-1] or 0)
    if price <= 0:
        return {"active": False}
    change5 = (price - prices[-6]) / prices[-6] * 100.0 if prices[-6] else 0.0
    change10 = (price - prices[-11]) / prices[-11] * 100.0 if len(prices) >= 11 and prices[-11] else change5
    if abs(change5) < 1.1 and abs(change10) < 1.8:
        return {"active": False, "change5": change5, "change10": change10}
    direction = "快速拉升" if change5 > 0 or change10 > 0 else "快速下跌"
    news = fetch_urgent_stock_news(name, code, direction)
    return {
        "active": True,
        "direction": direction,
        "change5": round(change5, 2),
        "change10": round(change10, 2),
        **news,
    }


def fetch_urgent_stock_news(name: str, code: str, direction: str) -> dict:
    cache_key = f"{code}:{direction}"
    now_ts = datetime.now().timestamp()
    cached = URGENT_NEWS_CACHE.get(cache_key)
    if cached and now_ts - float(cached.get("ts") or 0) < 600:
        return dict(cached.get("data") or {})
    query = f"{name} {code} 公告 利好 利空 业绩 减持 增持 事故"
    titles: list[str] = []
    for url in urgent_news_urls(query):
        try:
            req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
            text = urllib.request.urlopen(req, timeout=4).read().decode("utf-8", "replace")
            for raw in re.findall(r"<title><!\[CDATA\[(.*?)\]\]></title>|<title>(.*?)</title>", text, flags=re.I | re.S):
                title = html_lib.unescape((raw[0] or raw[1] or "").strip())
                title = re.sub(r"\s+", " ", title)
                if title and "Google" not in title and "Bing" not in title:
                    titles.append(title)
            if titles:
                break
        except Exception:
            continue
    result = classify_urgent_news(titles, direction)
    URGENT_NEWS_CACHE[cache_key] = {"ts": now_ts, "data": result}
    return result


def urgent_news_urls(query: str) -> list[str]:
    q = urllib.parse.quote(query)
    return [
        f"https://news.google.com/rss/search?q={q}&hl=zh-CN&gl=CN&ceid=CN:zh-Hans",
        f"https://www.bing.com/news/search?q={q}&format=rss&setlang=zh-CN&cc=CN",
    ]


def classify_urgent_news(titles: list[str], direction: str) -> dict:
    bull_words = ("利好", "增持", "回购", "中标", "获批", "并购", "预增", "增长", "新高", "资源", "金价", "铜价")
    bear_words = ("利空", "减持", "处罚", "立案", "亏损", "下滑", "事故", "停产", "问询", "监管", "解禁", "债务")
    for title in titles[:8]:
        if any(word in title for word in bear_words):
            return {"bias": "偏利空", "headline": shorten_sentence(title, 46), "checked": True}
        if any(word in title for word in bull_words):
            return {"bias": "偏利好", "headline": shorten_sentence(title, 46), "checked": True}
    headline = shorten_sentence(titles[0], 46) if titles else ""
    return {"bias": "未发现突发消息", "headline": headline, "checked": bool(titles)}


def rapid_news_agent(news: dict) -> str:
    direction = news.get("direction") or "快速异动"
    change5 = float(news.get("change5") or 0)
    bias = news.get("bias") or "未发现突发消息"
    headline = news.get("headline") or "暂无可用标题"
    if direction == "快速拉升":
        action = "有利好也不追高，等回踩黄线；无利好按资金脉冲处理"
    else:
        action = "有利空先降级观察；无利空等止跌拐头和黄线确认"
    return f"消息员：{direction}，近5分钟{change5:+.2f}%；新闻核验：{bias}；{headline}；{action}"


def news_adjusted_signal(action: str, reason: str, news: dict) -> tuple[str, str]:
    if not news.get("active"):
        return action, reason
    direction = str(news.get("direction") or "快速异动")
    bias = str(news.get("bias") or "未发现突发消息")
    headline = str(news.get("headline") or "暂无可用标题")
    prefix = f"异动核验：{direction}，{bias}，{headline}。"
    buy_like = any(word in action for word in ("低吸", "买入"))
    sell_like = any(word in action for word in ("高抛", "卖出", "高位"))
    if direction == "快速下跌" and bias == "偏利空" and buy_like:
        return "消息观察", prefix + "低吸信号降级，等止跌拐头和黄线重新站稳。"
    if direction == "快速下跌" and buy_like:
        return action, prefix + "未见明确利空，但仍需二次止跌确认；" + reason
    if direction == "快速拉升" and sell_like and bias == "偏利好":
        return action, prefix + "利好配合上涨，高抛只做减仓，不做重仓反向；" + reason
    if direction == "快速拉升" and not sell_like:
        return "脉冲观察", prefix + "先不追涨，等回踩黄线或放量滞涨再判断。"
    return action, prefix + reason


def fetch_yahoo_market(name: str, symbol: str, unit: str, weight: float) -> dict | None:
    try:
        encoded = urllib.parse.quote(symbol, safe="")
        url = f"https://query1.finance.yahoo.com/v8/finance/chart/{encoded}?range=2d&interval=5m"
        req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
        data = json.loads(urllib.request.urlopen(req, timeout=8).read().decode("utf-8", "replace"))
        result = (data.get("chart", {}).get("result") or [None])[0] or {}
        meta = result.get("meta", {})
        price = float(meta.get("regularMarketPrice") or 0)
        prev = float(meta.get("chartPreviousClose") or meta.get("previousClose") or 0)
        change = (price - prev) / prev * 100 if price and prev else 0.0
        ts = int(meta.get("regularMarketTime") or 0)
        age_minutes = round((datetime.now().timestamp() - ts) / 60, 1) if ts else 99999
        quote_time = datetime.fromtimestamp(ts, timezone(timedelta(hours=8))).strftime("%m-%d %H:%M") if ts else ""
        return {"name": name, "symbol": symbol, "price": price, "change": change, "unit": unit, "weight": weight, "time": quote_time, "ageMinutes": age_minutes, "isStale": age_minutes > 180, "source": "Yahoo 5分钟快照"}
    except Exception:
        return None


def zijin_premarket_bias(rows: list[dict]) -> dict:
    return premarket_stock_bias(rows, {"name": "紫金矿业", "code": "601899", "symbol": "sh601899"})


def premarket_stock_bias(rows: list[dict], target: dict) -> dict:
    stock_name = str(target.get("name") or "目标股票")
    code = str(target.get("code") or "")
    category = premarket_stock_category(stock_name, code)
    by_name = {row["name"]: row for row in rows}
    score = 50.0
    reasons: list[str] = []
    weights = premarket_factor_weights(category)
    for name in ("黄金", "白银", "铜", "WTI原油", "布油", "美元指数", "离岸人民币"):
        row = by_name.get(name)
        if not row:
            continue
        change = float(row.get("change") or 0)
        weight = float(weights.get(name, 0))
        if not weight:
            continue
        score += change * weight * 5
        if abs(change) >= (0.25 if name in {"美元指数", "离岸人民币"} else 0.5):
            direction = "利好" if change * weight > 0 else "压制"
            reasons.append(f"{name}{change:+.2f}%，{direction}{category}情绪")
    score = max(0, min(100, score))
    if score >= 68:
        signal = "偏多"
        action = f"{stock_name}开盘可重点观察，等黄线承接后再做T"
    elif score <= 42:
        signal = "偏空"
        action = f"{stock_name}开盘先防守，低于黄线不急着接"
    else:
        signal = "观望"
        action = "外盘方向不强，盘中按黄线和量能确认"
    if not reasons:
        reasons = ["外盘快照不足，先按盘中黄线和成交量判断"]
    return {"name": stock_name, "code": code, "category": category, "score": round(score, 1), "signal": signal, "action": action, "reasons": reasons[:4]}


def premarket_stock_category(name: str, code: str) -> str:
    text = f"{name}{code}"
    if any(word in text for word in ("紫金", "钼", "铜", "铝", "金", "矿", "有色", "神华", "煤", "能源", "石油")):
        return "资源周期"
    if any(word in text for word in ("隆基", "新能源", "光伏", "电池", "锂", "储能")):
        return "新能源"
    if any(word in text for word in ("电驱", "汽车", "机器人", "智能", "制造", "电机")):
        return "高端制造"
    if any(word in text for word in ("中兴", "新易盛", "通信", "电子", "芯", "数据", "软件")):
        return "科技成长"
    return "综合观察"


def premarket_factor_weights(category: str) -> dict:
    if category == "资源周期":
        return {"黄金": 1.8, "白银": 0.7, "铜": 2.1, "WTI原油": 0.4, "布油": 0.3, "美元指数": -1.5, "离岸人民币": -0.5}
    if category == "新能源":
        return {"铜": 0.8, "WTI原油": -0.3, "布油": -0.2, "美元指数": -0.7, "离岸人民币": -0.4}
    if category == "高端制造":
        return {"铜": 0.6, "WTI原油": -0.2, "美元指数": -0.6, "离岸人民币": -0.5}
    if category == "科技成长":
        return {"铜": 0.3, "美元指数": -0.8, "离岸人民币": -0.5}
    return {"铜": 0.4, "WTI原油": 0.2, "美元指数": -0.6, "离岸人民币": -0.3}


def smart_money_payload(quote, minutes: list, avg: float | None, dev: float) -> dict:
    """Phase 1 smart-money approximation from ordinary minute bars.

    This is intentionally conservative because we do not have full tick/order-book data.
    It estimates absorption, program push, and distribution from price response and volume.
    """
    if not quote or not minutes or len(minutes) < 8:
        return {"text": "主力行为：数据不足，普通行情模式。", "confidence": 20}
    prices = [m.price for m in minutes if getattr(m, "price", 0) > 0]
    vols = _bar_volume_deltas(minutes)
    if len(prices) < 8 or len(vols) < 8:
        return {"text": "主力行为：数据不足，普通行情模式。", "confidence": 20}
    recent = prices[-8:]
    recent_vol = vols[-8:]
    prev_vol = vols[-16:-8] if len(vols) >= 16 else vols[:-8]
    vol_base = sum(prev_vol) / len(prev_vol) if prev_vol else max(sum(vols) / len(vols), 1)
    vol_ratio = min(max((sum(recent_vol) / len(recent_vol)) / max(vol_base, 1), 0), 5)
    drift = (recent[-1] - recent[0]) / recent[0] * 100 if recent[0] else 0
    higher_low = min(recent[-4:]) >= min(recent[:4])
    failed_high = max(recent[-4:]) <= max(recent[:4]) * 1.002
    above_vwap = bool(avg and quote.price >= avg)

    accumulation = 30 + (22 if higher_low else 0) + (18 if dev < 0 and quote.price > min(recent) else 0) + int(vol_ratio * 5)
    program_push = 25 + (24 if drift > 0.35 else 0) + (14 if above_vwap else 0) + int(vol_ratio * 6)
    distribution = 25 + (22 if quote.change_pct > 1 and failed_high else 0) + (18 if dev > 0.8 and vol_ratio > 1.1 else 0)
    accumulation = max(0, min(100, accumulation))
    program_push = max(0, min(100, program_push))
    distribution = max(0, min(100, distribution))
    scores = {"吸筹承接": accumulation, "程序化推升": program_push, "高位派发": distribution}
    label, score = max(scores.items(), key=lambda item: item[1])
    confidence = max(35, min(78, score - 8))
    bias = "偏多" if label in {"吸筹承接", "程序化推升"} else "风险"
    return {
        "text": f"主力行为：疑似{label} {score}%｜方向{bias}｜可信度{confidence}%（普通分时降级判断）",
        "confidence": confidence,
        "accumulation": accumulation,
        "programPush": program_push,
        "distribution": distribution,
    }


def monitor_agents_payload(name: str, quote, minutes: list, avg: float | None, dev: float, signal, is_open: bool, market_context: dict | None = None, gemini_advice: dict | None = None) -> list[str]:
    if not is_open:
        ai_text = ""
        if gemini_advice:
            macro, path, action = compact_ai_advice(gemini_advice)
            ai_text = f"；Gemini参考：{macro}，路径{path}，{action}"
        return [
            "技术员：休市中，仅展示最近分时",
            "资金员：等待开盘后重新计算量价",
            "外盘员：金银铜油美元仅作次日参考" + ai_text,
            "风控员：休市不触发买卖提醒",
            "决策员：观察，盘前/盘后以大方向预案为主",
        ]
    price = float(getattr(quote, "price", 0) or 0)
    change = float(getattr(quote, "change_pct", 0) or 0)
    action = str(getattr(signal, "action", "") or "观察")
    reason = str(getattr(signal, "reason", "") or "暂无高质量买卖点")
    prices = [float(getattr(m, "price", 0) or 0) for m in minutes if float(getattr(m, "price", 0) or 0) > 0]
    day_high = max(prices) if prices else price
    day_low = min(prices) if prices else price
    lift = (price - day_low) / day_low * 100.0 if day_low > 0 else 0.0
    fade = (day_high - price) / day_high * 100.0 if day_high > 0 else 0.0
    swing = (day_high - day_low) / day_low * 100.0 if day_low > 0 else 0.0
    tech = "趋势偏强" if change > 0.8 else "趋势偏弱" if change < -0.8 else "震荡观察"
    if avg and price:
        pos = "黄线上方" if price >= avg else "黄线下方"
        tech += f"，{pos}{dev:+.2f}%，日内{day_low:.2f}-{day_high:.2f}，振幅{swing:.2f}%"
    money = "分时数据不足，先观察量价"
    vol_detail = ""
    if minutes and len(minutes) >= 8:
        vols = _bar_volume_deltas(minutes)
        recent_vol = sum(vols[-5:]) / max(1, len(vols[-5:]))
        base_vol = sum(vols[:-5]) / max(1, len(vols[:-5])) if len(vols) > 5 else recent_vol
        ratio = recent_vol / max(base_vol, 1)
        recent_prices = prices[-6:] if len(prices) >= 6 else prices
        recent_change = (recent_prices[-1] - recent_prices[0]) / recent_prices[0] * 100.0 if len(recent_prices) >= 2 and recent_prices[0] else 0.0
        vol_detail = f"近5分钟量比{ratio:.2f}x，价格{recent_change:+.2f}%"
        if ratio >= 1.4:
            money = f"成交放大，{vol_detail}，若放量滞涨要防高位派发"
        elif ratio >= 0.8:
            money = f"量能正常，{vol_detail}，看能否站稳黄线"
        else:
            money = f"量能收缩，{vol_detail}，谨防无量冲高或假突破"
    futures = market_link_payload(name, market_context)
    ai_macro = ""
    ai_path = ""
    ai_action = ""
    if gemini_advice:
        ai_macro, ai_path, ai_action = compact_ai_advice(gemini_advice)
        if ai_macro or ai_path:
            futures += f"；Gemini大方向：{ai_macro or '观察'}，路径：{ai_path or '待确认'}"
    tradable = any(word in action for word in ("低吸", "高抛", "买入", "卖出"))
    if "卖" in action or "高抛" in action:
        risk = f"卖出信号后不追高，若跌回黄线/计划价再接；当前距日高回落{fade:.2f}%"
    elif "买" in action or "低吸" in action:
        risk = f"买入信号先看止跌，不把做T变补仓；当前距日低反弹{lift:.2f}%"
    else:
        risk = "未达强信号，避免频繁提醒"
    decision = f"{action}｜{reason}"
    if ai_action:
        decision += f"｜AI意见：{ai_action[:80]}"
    if tradable:
        decision += "｜提醒已按同方向限频，防止刷屏"
    return [
        f"技术员：{tech}",
        f"资金员：{money}",
        f"外盘员：{futures}",
        f"风控员：{risk}",
        f"决策员：{decision}",
    ]


def compact_ai_advice(gemini_advice: dict) -> tuple[str, str, str]:
    analysis = gemini_advice.get("analysis") or {}
    macro = str(analysis.get("macroView") or "观察").strip()
    path_value = analysis.get("pathForecast") or "待确认"
    if isinstance(path_value, dict):
        path = str(path_value.get("mostLikely") or path_value.get("主路径") or next(iter(path_value.values()), "待确认"))
    else:
        path = str(path_value)
    action = str(analysis.get("action") or "等待价格验证").strip()
    return shorten_sentence(macro, 42), shorten_sentence(path, 46), shorten_sentence(action, 36)


def shorten_sentence(text: str, limit: int) -> str:
    text = re.sub(r"\s+", "", str(text or "")).strip("；。 ")
    return text if len(text) <= limit else text[:limit] + "..."


def market_link_payload(name: str, market_context: dict | None) -> str:
    rows = (market_context or {}).get("rows") or []
    by_name = {row.get("name"): row for row in rows if isinstance(row, dict)}
    parts = []
    for key in ("黄金", "铜", "美元指数", "WTI原油"):
        row = by_name.get(key)
        if not row:
            continue
        change = float(row.get("change") or 0)
        parts.append(f"{key}{change:+.2f}%")
    bias = ((market_context or {}).get("zijin") or {}).get("signal") or "观望"
    if "紫金" in name or "矿" in name or "钼" in name:
        if parts:
            return f"{'，'.join(parts)}；资源股外盘倾向{bias}，盘中仍以黄线和量能确认"
        return "外盘快照暂缺，资源股先按金铜和美元方向人工复核"
    if parts:
        return f"大宗/美元背景：{'，'.join(parts)}，对非资源股只作风险偏好参考"
    return "外盘快照暂缺，先看个股分时量价"


def gemini_intraday_payload(code: str) -> dict:
    key = load_gemini_key()
    if not key:
        return {"ok": False, "message": "未读取到 Gemini Key，无法进行盘中AI研判。"}
    try:
        from monitor_config import load_watchlist, parse_stock_token
        from stock_t_signal import analyze_observation, fetch_minutes, fetch_quote, _format_time, _vwap
    except Exception as exc:
        return {"ok": False, "message": f"监控模块读取失败：{exc}"}

    parsed_stock = parse_stock_token(code)
    symbol = parsed_stock.symbol if parsed_stock else ""
    raw_code = parsed_stock.code if parsed_stock else str(code).strip()[-6:]
    watchlist = load_watchlist()
    stock = next((item for item in watchlist if item.symbol == symbol or item.code == raw_code), None)
    if stock is None:
        stock = parsed_stock
    if stock is None:
        prefix = "sh" if raw_code.startswith(("5", "6")) else "sz"
        symbol = prefix + raw_code
        stock = type("StockLike", (), {"name": stock_name_local(symbol[-6:]), "code": symbol[-6:], "symbol": symbol})()
    try:
        quote = fetch_quote(stock.symbol)
        minutes = fetch_minutes(stock.symbol)
        if not quote:
            return {"ok": False, "message": "暂时没有读取到实时行情。"}
        avg = _vwap(quote, minutes)
        signals = analyze_observation(stock)
        signal = signals[0] if signals else None
        prices = [float(m.price) for m in minutes if float(m.price) > 0]
        day_high = max(prices) if prices else float(quote.high or quote.price)
        day_low = min(prices) if prices else float(quote.low or quote.price)
        dev = (quote.price - avg) / avg * 100 if avg else 0.0
        swing = (day_high - day_low) / day_low * 100 if day_low else 0.0
        vols = _bar_volume_deltas(minutes)
        vol_ratio = 0.0
        if len(vols) >= 8:
            recent = sum(vols[-5:]) / max(1, len(vols[-5:]))
            base = sum(vols[:-5]) / max(1, len(vols[:-5])) if len(vols) > 5 else recent
            vol_ratio = recent / max(base, 1)
        market_context = cached_market_context()
        market_text = market_link_payload(stock.name, market_context)
        local_agents = monitor_agents_payload(stock.name, quote, minutes, avg, dev, signal, market_is_open(), market_context)
        compact = {
            "股票": f"{stock.name}{stock.code}",
            "时间": _format_time(quote.time_raw, minutes),
            "现价": round(float(quote.price), 3),
            "昨收": round(float(getattr(quote, "pre_close", 0) or 0), 3),
            "涨跌幅": round(float(quote.change_pct), 2),
            "黄线均价": round(float(avg or 0), 3),
            "黄线偏离": round(dev, 2),
            "日内低点": round(day_low, 3),
            "日内高点": round(day_high, 3),
            "日内振幅": round(swing, 2),
            "近5分钟量比": round(vol_ratio, 2),
            "本地信号": getattr(signal, "action", "观察") if signal else "观察",
            "本地原因": getattr(signal, "reason", "暂无高质量买卖点") if signal else "暂无高质量买卖点",
            "外盘": market_text,
            "本地多角色": local_agents,
        }
        prompt = (
            "你是A股盘前、盘中和盘后方向研判助手，先判断全天大方向和最可能路径，再判断是否适合做T。"
            "重点围绕市场风险偏好、资源品方向、黄金/铜/美元/原油、分时黄线/VWAP、量价、日内高低点。"
            "必须判断今天更像：高开低走、低开高走、冲高回落、探底回升、震荡洗盘、趋势推进、无方向。"
            "如果本地信号不是观察，必须集中讨论这个买卖点是否最优：是否太早、是否追高/接刀、是否需要等更好价格。"
            "原则：上涨到高位后，优先等回踩/反抽不过再卖；下探到低位后，优先等回踩不破/二次拐头再买；只有急转直下或急速V反才允许快速执行。"
            "请严格输出JSON，字段为 macroView, pathForecast, keyPrices, pointReview, trend, action, buyPlan, sellPlan, invalidation, agents。"
            "pathForecast要给最可能路径和备选路径；keyPrices要给支撑、压力、黄线、低吸价、高抛价。"
            "pointReview要明确写：最优/可做但不最优/放弃，并给一句原因。"
            "agents数组正好5行，分别以技术员、资金员、外盘员、风控员、决策员开头。"
            "macroView要说明大方向偏多/偏空/震荡和原因；要求中文、简洁、给具体价格；不要承诺收益；如果证据不足就说观察。数据："
            + json.dumps(compact, ensure_ascii=False)
        )
        payload = {
            "contents": [{"parts": [{"text": prompt}]}],
            "generationConfig": {
                "temperature": 0.15,
                "maxOutputTokens": 900,
                "responseMimeType": "application/json",
                "thinkingConfig": {"thinkingBudget": 0},
            },
        }
        ai_config = load_ai_config()
        base = (ai_config.get("base") or load_desktop_env().get("GEMINI_API_BASE") or os.environ.get("GEMINI_API_BASE") or "https://generativelanguage.googleapis.com").rstrip("/")
        model = ai_config.get("model") or load_desktop_env().get("GEMINI_MODEL") or os.environ.get("GEMINI_MODEL") or "gemini-2.5-flash"
        req = urllib.request.Request(
            f"{base}/v1beta/models/{model}:generateContent?key={key}",
            data=json.dumps(payload).encode("utf-8"),
            headers={"Content-Type": "application/json"},
            method="POST",
        )
        data = json.loads(gemini_open(req, timeout=9).read().decode("utf-8", "replace"))
        text = data["candidates"][0]["content"]["parts"][0]["text"]
        parsed = parse_json_object(text)
        result = {"ok": True, "stock": compact, "analysis": parsed, "model": model, "message": "Gemini盘中研判完成。", "cachedAt": datetime.now().strftime("%H:%M")}
        GEMINI_INTRADAY_CACHE[stock.code] = {"ts": datetime.now().timestamp(), **result}
        return result
    except Exception as exc:
        return {"ok": False, "message": f"Gemini盘中研判失败：{type(exc).__name__}: {str(exc)[:260]}"}


def gemini_cached_advice(code: str, max_age_seconds: int = 30 * 60) -> dict | None:
    item = GEMINI_INTRADAY_CACHE.get(str(code)[-6:])
    if not item:
        return None
    if datetime.now().timestamp() - float(item.get("ts") or 0) > max_age_seconds:
        return None
    return item


